const Joi = require('joi');

/**
 * Get users validation
 */
exports.getUsers = Joi.object({
  query: Joi.object({
    page: Joi.number()
      .integer()
      .min(1)
      .default(1),
    limit: Joi.number()
      .integer()
      .min(1)
      .max(100)
      .default(10),
    sort: Joi.string()
      .valid('createdAt', '-createdAt', 'email', '-email', 'username', '-username')
      .default('-createdAt'),
    role: Joi.string()
      .valid('user', 'admin', 'manager')
      .optional(),
    isActive: Joi.boolean()
      .optional(),
    search: Joi.string()
      .min(2)
      .max(100)
      .optional()
  })
});

/**
 * Get user by ID validation
 */
exports.getUserById = Joi.object({
  params: Joi.object({
    id: Joi.number()
      .integer()
      .positive()
      .required()
      .messages({
        'number.base': 'User ID must be a number',
        'number.positive': 'User ID must be positive',
        'any.required': 'User ID is required'
      })
  })
});

/**
 * Create user validation
 */
exports.createUser = Joi.object({
  body: Joi.object({
    email: Joi.string()
      .email()
      .required(),
    username: Joi.string()
      .alphanum()
      .min(3)
      .max(30)
      .required(),
    password: Joi.string()
      .min(8)
      .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/)
      .required(),
    firstName: Joi.string()
      .min(2)
      .max(50)
      .optional(),
    lastName: Joi.string()
      .min(2)
      .max(50)
      .optional(),
    role: Joi.string()
      .valid('user', 'admin', 'manager')
      .default('user')
  })
});

/**
 * Update user validation
 */
exports.updateUser = Joi.object({
  params: Joi.object({
    id: Joi.number()
      .integer()
      .positive()
      .required()
  }),
  body: Joi.object({
    email: Joi.string()
      .email()
      .optional(),
    username: Joi.string()
      .alphanum()
      .min(3)
      .max(30)
      .optional(),
    firstName: Joi.string()
      .min(2)
      .max(50)
      .optional(),
    lastName: Joi.string()
      .min(2)
      .max(50)
      .optional(),
    role: Joi.string()
      .valid('user', 'admin', 'manager')
      .optional(),
    isActive: Joi.boolean()
      .optional()
  }).min(1) // At least one field must be provided
});

/**
 * Delete user validation
 */
exports.deleteUser = Joi.object({
  params: Joi.object({
    id: Joi.number()
      .integer()
      .positive()
      .required()
  })
});

/**
