Building on the deployment infrastructure from Section 9, this final section covers comprehensive monitoring and observability for your production REST API. Effective monitoring ensures you can detect, diagnose, and resolve issues before they impact users.

### 10.1 The Three Pillars of Observability

Modern observability is built on three pillars:

1. **Metrics** - Numerical measurements over time (CPU usage, request rate, error rate)
2. **Logs** - Discrete events with context (error messages, audit trails)
3. **Traces** - Request flow through distributed systems

### 10.2 Application Performance Monitoring (APM)

**Installing Prometheus Client**
```bash
npm install prom-client
npm install @types/prom-client --save-dev
```

**Metrics Service (src/services/metrics.service.ts)**
```typescript
import { Registry, Counter, Histogram, Gauge } from 'prom-client';

class MetricsService {
  public registry: Registry;

  // HTTP metrics
  public httpRequestDuration: Histogram;
  public httpRequestTotal: Counter;
  public httpRequestErrors: Counter;

  // Business metrics
  public activeUsers: Gauge;
  public authenticationAttempts: Counter;
  public validationErrors: Counter;
  public databaseQueryDuration: Histogram;

  constructor() {
    this.registry = new Registry();

    // HTTP request duration histogram
    this.httpRequestDuration = new Histogram({
      name: 'http_request_duration_seconds',
      help: 'Duration of HTTP requests in seconds',
      labelNames: ['method', 'route', 'status_code'],
      buckets: [0.1, 0.5, 1, 2, 5, 10],
      registers: [this.registry],
    });

    // HTTP request counter
    this.httpRequestTotal = new Counter({
      name: 'http_requests_total',
      help: 'Total number of HTTP requests',
      labelNames: ['method', 'route', 'status_code'],
      registers: [this.registry],
    });

    // HTTP error counter
    this.httpRequestErrors = new Counter({
      name: 'http_request_errors_total',
      help: 'Total number of HTTP request errors',
      labelNames: ['method', 'route', 'error_type'],
      registers: [this.registry],
    });

    // Active users gauge
    this.activeUsers = new Gauge({
      name: 'active_users_total',
      help: 'Number of currently active users',
      registers: [this.registry],
    });

    // Authentication attempts
    this.authenticationAttempts = new Counter({
      name: 'authentication_attempts_total',
      help: 'Total authentication attempts',
      labelNames: ['status', 'method'],
      registers: [this.registry],
    });

    // Validation errors from Section 6
    this.validationErrors = new Counter({
      name: 'validation_errors_total',
      help: 'Total validation errors',
      labelNames: ['field', 'error_type'],
      registers: [this.registry],
    });

    // Database query duration from Section 4
    this.databaseQueryDuration = new Histogram({
      name: 'database_query_duration_seconds',
      help: 'Duration of database queries',
      labelNames: ['operation', 'model'],
      buckets: [0.01, 0.05, 0.1, 0.5, 1, 2],
      registers: [this.registry],
    });
  }

  getMetrics(): Promise<string> {
    return this.registry.metrics();
  }
}

export const metricsService = new MetricsService();
```

**Metrics Middleware (src/middleware/metrics.middleware.ts)**
```typescript
import { Request, Response, NextFunction } from 'express';
import { metricsService } from '../services/metrics.service';

export const metricsMiddleware = (
  req: Request,
  res: Response,
  next: NextFunction
) => {
  const start = Date.now();

  // Capture response finish event
  res.on('finish', () => {
    const duration = (Date.now() - start) / 1000;
    const route = req.route?.path || req.path;

    // Record metrics
    metricsService.httpRequestDuration.observe(
      {
        method: req.method,
        route,
        status_code: res.statusCode,
      },
      duration
    );

    metricsService.httpRequestTotal.inc({
      method: req.method,
      route,
      status_code: res.statusCode,
    });

    // Track errors (4xx and 5xx)
    if (res.statusCode >= 400) {
      metricsService.httpRequestErrors.inc({
        method: req.method,
        route,
        error_type: res.statusCode >= 500 ? 'server_error' : 'client_error',
      });
    }
  });

  next();
};
```

**Metrics Endpoint (src/routes/metrics.routes.ts)**
```typescript
import { Router, Request, Response } from 'express';
import { metricsService } from '../services/metrics.service';

const router = Router();

router.get('/metrics', async (req: Request, res: Response) => {
  res.set('Content-Type', metricsService.registry.contentType);
  const metrics = await metricsService.getMetrics();
  res.send(metrics);
});

export default router;
```

### 10.3 Health Check Endpoints

**Enhanced Health Checks (src/routes/health.routes.ts)**
```typescript
import { Router, Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';

const router = Router();
const prisma = new PrismaClient();

// Liveness probe - is the app running?
router.get('/health/live', (req: Request, res: Response) => {
  res.status(200).json({
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  });
});

// Readiness probe - is the app ready to serve traffic?
router.get('/health/ready', async (req: Request, res: Response) => {
  const checks = {
    database: false,
    memory: false,
  };

  try {
    // Check database connection from Section 4
    await prisma.$queryRaw`SELECT 1`;
    checks.database = true;

    // Check memory usage
    const memUsage = process.memoryUsage();
    const memThreshold = 0.9; // 90% threshold
    checks.memory = memUsage.heapUsed / memUsage.heapTotal < memThreshold;

    const isReady = Object.values(checks).every(check => check);

    res.status(isReady ? 200 : 503).json({
      status: isReady ? 'ready' : 'not_ready',
      checks,
      timestamp: new Date().toISOString(),
    });
  } catch (error) {
    res.status(503).json({
      status: 'not_ready',
      checks,
      error: 'Health check failed',
      timestamp: new Date().toISOString(),
    });
  }
});

// Detailed health check
router.get('/health', async (req: Request, res: Response) => {
  const health = {
    status: 'healthy',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
    environment: process.env.NODE_ENV,
    version: process.env.APP_VERSION || '1.0.0',
    checks: {
      database: { status: 'unknown', responseTime: 0 },
      memory: { status: 'unknown', usage: {} },
      cpu: { status: 'unknown', usage: 0 },
    },
  };

  try {
    // Database check
    const dbStart = Date.now();
    await prisma.$queryRaw`SELECT 1`;
    health.checks.database = {
      status: 'healthy',
      responseTime: Date.now() - dbStart,
    };

    // Memory check
    const memUsage = process.memoryUsage();
    health.checks.memory = {
      status: memUsage.heapUsed / memUsage.heapTotal < 0.9 ? 'healthy' : 'warning',
      usage: {
        heapUsed: `${Math.round(memUsage.heapUsed / 1024 / 1024)}MB`,
        heapTotal: `${Math.round(memUsage.heapTotal / 1024 / 1024)}MB`,
        external: `${Math.round(memUsage.external / 1024 / 1024)}MB`,
      },
    };

    // CPU check
    const cpuUsage = process.cpuUsage();
    health.checks.cpu = {
      status: 'healthy',
      usage: cpuUsage.user + cpuUsage.system,
    };

    res.status(200).json(health);
  } catch (error) {
    health.status = 'unhealthy';
    res.status(503).json(health);
  }
});

export default router;
```

### 10.4 Error Tracking with Sentry

**Installing Sentry**
```bash
npm install @sentry/node @sentry/tracing
```

**Sentry Configuration (src/config/sentry.config.ts)**
```typescript
import * as Sentry from '@sentry/node';
import * as Tracing from '@sentry/tracing';
import { Express } from 'express';

export const initSentry = (app: Express) => {
  Sentry.init({
    dsn: process.env.SENTRY_DSN,
    environment: process.env.NODE_ENV,
    tracesSampleRate: process.env.NODE_ENV === 'production' ? 0.1 : 1.0,
    integrations: [
      new Sentry.Integrations.Http({ tracing: true }),
      new Tracing.Integrations.Express({ app }),
      new Tracing.Integrations.Prisma({ client: prisma }),
    ],
    beforeSend(event, hint) {
      // Filter out sensitive data
      if (event.request) {
        delete event.request.cookies;
        if (event.request.headers) {
          delete event.request.headers.authorization;
        }
      }
      return event;
    },
  });

  // Request handler must be first
  app.use(Sentry.Handlers.requestHandler());
  app.use(Sentry.Handlers.tracingHandler());
};

export const sentryErrorHandler = Sentry.Handlers.errorHandler();
```

**Integration with Error Handler from Section 7**
```typescript
// src/middleware/error.middleware.ts
import { Request, Response, NextFunction } from 'express';
import * as Sentry from '@sentry/node';
import { AppError } from '../utils/errors';
import { logger } from '../utils/logger';

export const errorHandler = (
  err: Error,
  req: Request,
  res: Response,
  next: NextFunction
) => {
  // Log error
  logger.error('Error occurred', {
    error: err.message,
    stack: err.stack,
    path: req.path,
    method: req.method,
  });

  // Send to Sentry for operational errors
  if (err instanceof AppError && err.isOperational) {
    Sentry.captureException(err, {
      tags: {
        errorType: err.constructor.name,
        statusCode: err.statusCode,
      },
      user: req.user ? { id: req.user.id, email: req.user.email } : undefined,
      extra: {
        path: req.path,
        method: req.method,
        body: req.body,
      },
    });
  } else {
    // Critical errors
    Sentry.captureException(err, { level: 'fatal' });
  }

  // Send response
  const statusCode = err instanceof AppError ? err.statusCode : 500;
  res.status(statusCode).json({
    status: 'error',
    message: err.message,
    ...(process.env.NODE_ENV === 'development' && { stack: err.stack }),
  });
};
```

### 10.5 Logging Aggregation

**Winston with Log Levels (src/utils/logger.ts)**
```typescript
import winston from 'winston';
import DailyRotateFile from 'winston-daily-rotate-file';

const logFormat = winston.format.combine(
  winston.format.timestamp(),
  winston.format.errors({ stack: true }),
  winston.format.json()
);

export const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: logFormat,
  defaultMeta: {
    service: 'rest-api',
    environment: process.env.NODE_ENV,
  },
  transports: [
    // Console transport
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      ),
    }),

    // Error log file
    new DailyRotateFile({
      filename: 'logs/error-%DATE%.log',
      datePattern: 'YYYY-MM-DD',
      level: 'error',
      maxFiles: '30d',
      maxSize: '20m',
    }),

    // Combined log file
    new DailyRotateFile({
      filename: 'logs/combined-%DATE%.log',
      datePattern: 'YYYY-MM-DD',
      maxFiles: '14d',
      maxSize: '20m',
    }),
  ],
});

// Add request context
export const logWithContext = (level: string, message: string, meta: any) => {
  logger.log(level, message, {
    ...meta,
    timestamp: new Date().toISOString(),
    requestId: meta.requestId,
  });
};
```

**Request Logging Middleware**
```typescript
// src/middleware/logging.middleware.ts
import { Request, Response, NextFunction } from 'express';
import { logger } from '../utils/logger';
import { v4 as uuidv4 } from 'uuid';

export const requestLoggingMiddleware = (
  req: Request,
  res: Response,
  next: NextFunction
) => {
  const requestId = uuidv4();
  req.requestId = requestId;

  const start = Date.now();

  // Log request
  logger.info('Incoming request', {
    requestId,
    method: req.method,
    path: req.path,
    query: req.query,
    ip: req.ip,
    userAgent: req.get('user-agent'),
  });

  // Log response
  res.on('finish', () => {
    const duration = Date.now() - start;
    logger.info('Request completed', {
      requestId,
      method: req.method,
      path: req.path,
      statusCode: res.statusCode,
      duration: `${duration}ms`,
    });
  });

  next();
};
```

