### 5.3 Auth Controller

**src/controllers/auth.controller.js:**
```javascript
const authService = require('../services/auth.service');
const ApiResponse = require('../utils/ApiResponse');
const asyncHandler = require('../utils/asyncHandler');

/**
 * Register new user
 */
exports.register = asyncHandler(async (req, res) => {
  const result = await authService.register(req.body);

  res.status(201).json(
    new ApiResponse(201, result, 'User registered successfully')
  );
});

/**
 * Login user
 */
exports.login = asyncHandler(async (req, res) => {
  const { email, password } = req.body;
  const ipAddress = req.ip;
  const userAgent = req.get('user-agent');

  const result = await authService.login(email, password, ipAddress, userAgent);

  // Set refresh token in HTTP-only cookie
  res.cookie('refreshToken', result.refreshToken, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
  });

  res.status(200).json(
    new ApiResponse(200, {
      user: result.user,
      accessToken: result.accessToken,
    }, 'Login successful')
  );
});

/**
 * Logout user
 */
exports.logout = asyncHandler(async (req, res) => {
  const refreshToken = req.cookies.refreshToken || req.body.refreshToken;

  if (refreshToken) {
    await authService.logout(refreshToken);
  }

  res.clearCookie('refreshToken');

  res.status(200).json(
    new ApiResponse(200, null, 'Logout successful')
  );
});

/**
 * Refresh access token
 */
exports.refreshToken = asyncHandler(async (req, res) => {
  const refreshToken = req.cookies.refreshToken || req.body.refreshToken;

  const result = await authService.refreshAccessToken(refreshToken);

  res.status(200).json(
    new ApiResponse(200, result, 'Token refreshed successfully')
  );
});

/**
 * Forgot password
 */
exports.forgotPassword = asyncHandler(async (req, res) => {
  const { email } = req.body;

  const result = await authService.forgotPassword(email);

  res.status(200).json(
    new ApiResponse(200, null, result.message)
  );
});

/**
 * Reset password
 */
exports.resetPassword = asyncHandler(async (req, res) => {
  const { token, password } = req.body;

  const result = await authService.resetPassword(token, password);

  res.status(200).json(
    new ApiResponse(200, null, result.message)
  );
});

/**
 * Get current user
 */
exports.getCurrentUser = asyncHandler(async (req, res) => {
  res.status(200).json(
    new ApiResponse(200, req.user, 'User retrieved successfully')
  );
});

/**
 * Verify email
 */
exports.verifyEmail = asyncHandler(async (req, res) => {
  const { token } = req.params;

  const result = await authService.verifyEmail(token);

  res.status(200).json(
    new ApiResponse(200, null, result.message)
  );
});
```

### 5.4 OAuth Integration (Optional)

**src/services/oauth.service.js:**
```javascript
const axios = require('axios');
const User = require('../models/user.model');
const authService = require('./auth.service');
const ApiError = require('../utils/ApiError');

class OAuthService {
  /**
   * Google OAuth
   */
  static async googleAuth(code) {
    try {
      // Exchange code for tokens
      const tokenResponse = await axios.post(
        'https://oauth2.googleapis.com/token',
        {
          code,
          client_id: process.env.GOOGLE_CLIENT_ID,
          client_secret: process.env.GOOGLE_CLIENT_SECRET,
          redirect_uri: process.env.GOOGLE_REDIRECT_URI,
          grant_type: 'authorization_code',
        }
      );

      const { access_token } = tokenResponse.data;

      // Get user info
      const userResponse = await axios.get(
        'https://www.googleapis.com/oauth2/v2/userinfo',
        {
          headers: { Authorization: `Bearer ${access_token}` },
        }
      );

      const { email, name, picture } = userResponse.data;

      // Find or create user
      let user = await User.findByEmail(email);

      if (!user) {
        user = await User.create({
          email,
          username: email.split('@')[0],
          firstName: name.split(' ')[0],
          lastName: name.split(' ')[1] || '',
          password: crypto.randomBytes(32).toString('hex'), // Random password
          emailVerified: true,
          avatar: picture,
        });
      }

      // Generate tokens
      const accessToken = authService.generateAccessToken(user.id);
      const refreshToken = authService.generateRefreshToken();

      await RefreshToken.create({
        userId: user.id,
        token: refreshToken,
        expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
      });

      return {
        user: User.sanitize(user),
        accessToken,
        refreshToken,
      };
    } catch (error) {
      throw new ApiError(400, 'Google authentication failed');
    }
  }
}

module.exports = OAuthService;
```

