### 5.4 OAuth Integration (Optional)

**src/services/oauth.service.js:**
```javascript
const axios = require('axios');
const User = require('../models/user.model');
const { generateTokenPair } = require('../utils/jwt');
const ApiError = require('../utils/ApiError');

class OAuthService {
  /**
   * Google OAuth login
   */
  static async googleLogin(accessToken) {
    try {
      // Verify token with Google
      const response = await axios.get(
        `https://www.googleapis.com/oauth2/v3/userinfo?access_token=${accessToken}`
      );

      const { email, given_name, family_name, picture } = response.data;

      // Find or create user
      let user = await User.findByEmail(email);

      if (!user) {
        user = await User.create({
          email,
          first_name: given_name,
          last_name: family_name,
          password: crypto.randomBytes(32).toString('hex'), // Random password
          is_email_verified: true,
          oauth_provider: 'google',
          oauth_id: response.data.sub,
        });
      }

      // Generate tokens
      const tokens = generateTokenPair(user.id);

      delete user.password;

      return {
        user,
        tokens,
      };
    } catch (error) {
      throw new ApiError(401, 'Invalid Google access token');
    }
  }

  /**
   * GitHub OAuth login
   */
  static async githubLogin(code) {
    try {
      // Exchange code for access token
      const tokenResponse = await axios.post(
        'https://github.com/login/oauth/access_token',
        {
          client_id: process.env.GITHUB_CLIENT_ID,
          client_secret: process.env.GITHUB_CLIENT_SECRET,
          code,
        },
        {
          headers: {
            Accept: 'application/json',
          },
        }
      );

      const accessToken = tokenResponse.data.access_token;

      // Get user info
      const userResponse = await axios.get('https://api.github.com/user', {
        headers: {
          Authorization: `Bearer ${accessToken}`,
        },
      });

      const { email, name, avatar_url, id } = userResponse.data;

      // Find or create user
      let user = await User.findByEmail(email);

      if (!user) {
        const [firstName, ...lastNameParts] = name.split(' ');
        user = await User.create({
          email,
          first_name: firstName,
          last_name: lastNameParts.join(' '),
          password: crypto.randomBytes(32).toString('hex'),
          is_email_verified: true,
          oauth_provider: 'github',
          oauth_id: id.toString(),
        });
      }

      // Generate tokens
      const tokens = generateTokenPair(user.id);

      delete user.password;

      return {
        user,
        tokens,
      };
    } catch (error) {
      throw new ApiError(401, 'GitHub authentication failed');
    }
  }
}

module.exports = OAuthService;
```

