## 6. Validation

### 6.1 Request Validation with Joi

**src/validators/auth.validator.js:**
```javascript
const Joi = require('joi');

const register = Joi.object({
  body: Joi.object({
    email: Joi.string()
      .email()
      .required()
      .messages({
        'string.email': 'Please provide a valid email address',
        'any.required': 'Email is required',
      }),
    password: Joi.string()
      .min(8)
      .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/)
      .required()
      .messages({
        'string.min': 'Password must be at least 8 characters long',
        'string.pattern.base': 'Password must contain at least one uppercase letter, one lowercase letter, one number, and one special character',
        'any.required': 'Password is required',
      }),
    first_name: Joi.string()
      .min(2)
      .max(100)
      .required()
      .messages({
        'string.min': 'First name must be at least 2 characters long',
        'string.max': 'First name cannot exceed 100 characters',
        'any.required': 'First name is required',
      }),
    last_name: Joi.string()
      .min(2)
      .max(100)
      .required()
      .messages({
        'string.min': 'Last name must be at least 2 characters long',
        'string.max': 'Last name cannot exceed 100 characters',
        'any.required': 'Last name is required',
      }),
    phone: Joi.string()
      .pattern(/^\+?[1-9]\d{1,14}$/)
      .optional()
      .messages({
        'string.pattern.base': 'Please provide a valid phone number',
      }),
  }),
});

const login = Joi.object({
  body: Joi.object({
    email: Joi.string()
      .email()
      .required()
      .messages({
        'string.email': 'Please provide a valid email address',
        'any.required': 'Email is required',
      }),
    password: Joi.string()
      .required()
      .messages({
        'any.required': 'Password is required',
      }),
  }),
});

const refreshToken = Joi.object({
  body: Joi.object({
    refreshToken: Joi.string()
      .required()
      .messages({
        'any.required': 'Refresh token is required',
      }),
  }),
});

const forgotPassword = Joi.object({
  body: Joi.object({
    email: Joi.string()
      .email()
      .required()
      .messages({
        'string.email': 'Please provide a valid email address',
        'any.required': 'Email is required',
      }),
  }),
});

const resetPassword = Joi.object({
  params: Joi.object({
    token: Joi.string()
      .required()
      .messages({
        'any.required': 'Reset token is required',
      }),
  }),
  body: Joi.object({
    password: Joi.string()
      .min(8)
      .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/)
      .required()
      .messages({
        'string.min': 'Password must be at least 8 characters long',
        'string.pattern.base': 'Password must contain at least one uppercase letter, one lowercase letter, one number, and one special character',
        'any.required': 'Password is required',
      }),
  }),
});

const changePassword = Joi.object({
  body: Joi.object({
    currentPassword: Joi.string()
      .required()
      .messages({
        'any.required': 'Current password is required',
      }),
    newPassword: Joi.string()
      .min(8)
      .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/)
      .required()
      .invalid(Joi.ref('currentPassword'))
      .messages({
        'string.min': 'New password must be at least 8 characters long',
        'string.pattern.base': 'New password must contain at least one uppercase letter, one lowercase letter, one number, and one special character',
        'any.required': 'New password is required',
        'any.invalid': 'New password must be different from current password',
      }),
  }),
});

module.exports = {
  register,
  login,
  refreshToken,
  forgotPassword,
  resetPassword,
  changePassword,
};
```

**src/validators/user.validator.js:**
```javascript
const Joi = require('joi');

const getUserById = Joi.object({
  params: Joi.object({
    id: Joi.string()
      .uuid()
      .required()
      .messages({
        'string.guid': 'Invalid user ID format',
        'any.required': 'User ID is required',
      }),
  }),
});

const createUser = Joi.object({
  body: Joi.object({
    email: Joi.string()
      .email()
      .required(),
    password: Joi.string()
      .min(8)
      .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/)
      .required(),
    first_name: Joi.string()
      .min(2)
      .max(100)
      .required(),
    last_name: Joi.string()
      .min(2)
      .max(100)
      .required(),
    phone: Joi.string()
      .pattern(/^\+?[1-9]\d{1,14}$/)
      .optional(),
    role: Joi.string()
      .valid('user', 'admin', 'seller')
      .default('user'),
  }),
});

const updateUser = Joi.object({
  params: Joi.object({
    id: Joi.string()
      .uuid()
      .required(),
  }),
  body: Joi.object({
    first_name: Joi.string()
      .min(2)
      .max(100)
      .optional(),
    last_name: Joi.string()
      .min(2)
      .max(100)
      .optional(),
    phone: Joi.string()
      .pattern(/^\+?[1-9]\d{1,14}$/)
      .optional(),
    role: Joi.string()
      .valid('user', 'admin', 'seller')
      .optional(),
    is_active: Joi.boolean()
      .optional(),
  }).min(1),
});

const deleteUser = Joi.object({
  params: Joi.object({
    id: Joi.string()
      .uuid()
      .required(),
  }),
});

const updateProfile = Joi.object({
  body: Joi.object({
    first_name: Joi.string()
      .min(2)
      .max(100)
      .optional(),
    last_name: Joi.string()
      .min(2)
      .max(100)
      .optional(),
    phone: Joi.string()
      .pattern(/^\+?[1-9]\d{1,14}$/)
      .optional(),
  }).min(1),
});

module.exports = {
  getUserById,
  createUser,
  updateUser,
  deleteUser,
  updateProfile,
};
```

**src/validators/product.validator.js:**
```javascript
const Joi = require('joi');

const getProducts = Joi.object({
  query: Joi.object({
    page: Joi.number()
      .integer()
      .min(1)
      .default(1),
    limit: Joi.number()
      .integer()
      .min(1)
      .max(100)
      .default(10),
    sort: Joi.string()
      .valid('name', '-name', 'price', '-price', 'created_at', '-created_at')
      .default('-created_at'),
    status: Joi.string()
      .valid('draft', 'active', 'archived')
      .optional(),
    minPrice: Joi.number()
      .min(0)
      .optional(),
    maxPrice: Joi.number()
      .min(0)
      .optional(),
    search: Joi.string()
      .optional(),
    category: Joi.string()
      .optional(),
  }),
});

const getProductById = Joi.object({
  params: Joi.object({
    id: Joi.string()
      .uuid()
      .required()
      .messages({
        'string.guid': 'Invalid product ID format',
        'any.required': 'Product ID is required',
      }),
  }),
});

const createProduct = Joi.object({
  body: Joi.object({
    name: Joi.string()
      .min(3)
      .max(255)
      .required()
      .messages({
        'string.min': 'Product name must be at least 3 characters long',
        'string.max': 'Product name cannot exceed 255 characters',
        'any.required': 'Product name is required',
      }),
    slug: Joi.string()
      .pattern(/^[a-z0-9]+(?:-[a-z0-9]+)*$/)
      .required()
      .messages({
