Building on the deployment infrastructure from Section 9, monitoring is the final critical piece for maintaining a production-ready REST API. Effective monitoring provides visibility into your application's health, performance, and user experience, enabling proactive issue detection and rapid incident response.

### The Three Pillars of Observability

Modern monitoring is built on three interconnected pillars:

1. **Metrics**: Quantitative measurements (CPU usage, request rate, latency)
2. **Logs**: Discrete event records (errors, warnings, info messages)
3. **Traces**: Request flow through distributed systems

### Application Performance Monitoring (APM)

#### Setting Up Prometheus for Metrics

Prometheus is an industry-standard metrics collection and alerting system.

```typescript
// src/monitoring/metrics.ts
import promClient from 'prom-client';

// Create a Registry
export const register = new promClient.Registry();

// Add default metrics (CPU, memory, etc.)
promClient.collectDefaultMetrics({ register });

// Custom metrics
export const httpRequestDuration = new promClient.Histogram({
  name: 'http_request_duration_seconds',
  help: 'Duration of HTTP requests in seconds',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.1, 0.5, 1, 2, 5]
});

export const httpRequestTotal = new promClient.Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code']
});

export const activeConnections = new promClient.Gauge({
  name: 'active_connections',
  help: 'Number of active connections'
});

export const databaseQueryDuration = new promClient.Histogram({
  name: 'database_query_duration_seconds',
  help: 'Duration of database queries',
  labelNames: ['operation', 'table'],
  buckets: [0.01, 0.05, 0.1, 0.5, 1]
});

// Register all metrics
register.registerMetric(httpRequestDuration);
register.registerMetric(httpRequestTotal);
register.registerMetric(activeConnections);
register.registerMetric(databaseQueryDuration);
```

#### Metrics Collection Middleware

```typescript
// src/middleware/metrics.middleware.ts
import { Request, Response, NextFunction } from 'express';
import { httpRequestDuration, httpRequestTotal, activeConnections } from '../monitoring/metrics';

export const metricsMiddleware = (req: Request, res: Response, next: NextFunction) => {
  const start = Date.now();

  // Increment active connections
  activeConnections.inc();

  // Capture response
  res.on('finish', () => {
    const duration = (Date.now() - start) / 1000;
    const route = req.route?.path || req.path;

    // Record metrics
    httpRequestDuration.observe(
      { method: req.method, route, status_code: res.statusCode },
      duration
    );

    httpRequestTotal.inc({
      method: req.method,
      route,
      status_code: res.statusCode
    });

    // Decrement active connections
    activeConnections.dec();
  });

  next();
};
```

#### Metrics Endpoint

```typescript
// src/routes/metrics.routes.ts
import { Router } from 'express';
import { register } from '../monitoring/metrics';

const router = Router();

router.get('/metrics', async (req, res) => {
  res.setHeader('Content-Type', register.contentType);
  const metrics = await register.metrics();
  res.send(metrics);
});

export default router;
```

### Health Check Endpoints

Implement comprehensive health checks for monitoring systems and load balancers:

```typescript
// src/routes/health.routes.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import Redis from 'ioredis';

const router = Router();
const prisma = new PrismaClient();
const redis = new Redis(process.env.REDIS_URL);

// Liveness probe - is the app running?
router.get('/health/live', (req, res) => {
  res.status(200).json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Readiness probe - is the app ready to serve traffic?
router.get('/health/ready', async (req, res) => {
  const checks = {
    database: false,
    redis: false,
    memory: false
  };

  try {
    // Check database
    await prisma.$queryRaw`SELECT 1`;
    checks.database = true;

    // Check Redis
    await redis.ping();
    checks.redis = true;

    // Check memory usage
    const memUsage = process.memoryUsage();
    const memThreshold = 0.9; // 90% threshold
    checks.memory = (memUsage.heapUsed / memUsage.heapTotal) < memThreshold;

    const allHealthy = Object.values(checks).every(check => check === true);

    res.status(allHealthy ? 200 : 503).json({
      status: allHealthy ? 'ready' : 'not ready',
      checks,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    res.status(503).json({
      status: 'not ready',
      checks,
      error: error.message,
      timestamp: new Date().toISOString()
    });
  }
});

// Detailed health check
router.get('/health', async (req, res) => {
  const health = {
    uptime: process.uptime(),
    timestamp: new Date().toISOString(),
    status: 'ok',
    services: {},
    resources: {
      memory: process.memoryUsage(),
      cpu: process.cpuUsage()
    }
  };

  try {
    // Database health
    const dbStart = Date.now();
    await prisma.$queryRaw`SELECT 1`;
    health.services.database = {
      status: 'up',
      responseTime: Date.now() - dbStart
    };

    // Redis health
    const redisStart = Date.now();
    await redis.ping();
    health.services.redis = {
      status: 'up',
      responseTime: Date.now() - redisStart
    };

    res.status(200).json(health);
  } catch (error) {
    health.status = 'degraded';
    res.status(503).json(health);
  }
});

export default router;
```

### Logging Aggregation

#### Structured Logging with Winston

```typescript
// src/utils/logger.ts
import winston from 'winston';
import { ElasticsearchTransport } from 'winston-elasticsearch';

const esTransportOpts = {
  level: 'info',
  clientOpts: { node: process.env.ELASTICSEARCH_URL },
  index: 'api-logs'
};

export const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: {
    service: 'rest-api',
    environment: process.env.NODE_ENV
  },
  transports: [
    // Console output
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      )
    }),

    // File output
    new winston.transports.File({
      filename: 'logs/error.log',
      level: 'error'
    }),
    new winston.transports.File({
      filename: 'logs/combined.log'
    })
  ]
});

// Add Elasticsearch in production
if (process.env.NODE_ENV === 'production' && process.env.ELASTICSEARCH_URL) {
  logger.add(new ElasticsearchTransport(esTransportOpts));
}

// Request logging middleware
export const requestLogger = (req, res, next) => {
  const start = Date.now();

  res.on('finish', () => {
    logger.info('HTTP Request', {
      method: req.method,
      url: req.url,
      status: res.statusCode,
      duration: Date.now() - start,
      ip: req.ip,
      userAgent: req.get('user-agent'),
      userId: req.user?.id
    });
  });

  next();
};
```

### Distributed Tracing with OpenTelemetry

```typescript
// src/monitoring/tracing.ts
import { NodeSDK } from '@opentelemetry/sdk-node';
import { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node';
import { JaegerExporter } from '@opentelemetry/exporter-jaeger';
import { Resource } from '@opentelemetry/resources';
import { SemanticResourceAttributes } from '@opentelemetry/semantic-conventions';

const jaegerExporter = new JaegerExporter({
  endpoint: process.env.JAEGER_ENDPOINT || 'http://localhost:14268/api/traces'
});

export const sdk = new NodeSDK({
  resource: new Resource({
    [SemanticResourceAttributes.SERVICE_NAME]: 'rest-api',
    [SemanticResourceAttributes.SERVICE_VERSION]: process.env.APP_VERSION || '1.0.0'
  }),
  traceExporter: jaegerExporter,
  instrumentations: [
    getNodeAutoInstrumentations({
      '@opentelemetry/instrumentation-fs': { enabled: false }
    })
  ]
});

// Initialize tracing
export const initTracing = () => {
  sdk.start();

  process.on('SIGTERM', () => {
    sdk.shutdown()
      .then(() => console.log('Tracing terminated'))
      .catch((error) => console.error('Error terminating tracing', error));
  });
};
```

### Real-Time Alerting

#### Alerting Rules Configuration

```yaml
# prometheus/alerts.yml
groups:
  - name: api_alerts
    interval: 30s
    rules:
      # High error rate
      - alert: HighErrorRate
        expr: |
          rate(http_requests_total{status_code=~"5.."}[5m]) > 0.05
        for: 5m
        labels:
          severity: critical
        annotations:
          summary: "High error rate detected"
          description: "Error rate is {{ $value }} errors/sec"

      # High latency
      - alert: HighLatency
        expr: |
          histogram_quantile(0.95, 
            rate(http_request_duration_seconds_bucket[5m])
          ) > 2
        for: 5m
        labels:
          severity: warning
        annotations:
          summary: "High API latency"
          description: "95th percentile latency is {{ $value }}s"

      # Database connection issues
      - alert: DatabaseDown
        expr: up{job="database"} == 0
        for: 1m
        labels:
          severity: critical
        annotations:
          summary: "Database is down"

      # High memory usage
      - alert: HighMemoryUsage
        expr: |
          (process_resident_memory_bytes / 
           node_memory_MemTotal_bytes) > 0.9
        for: 5m
        labels:
          severity: warning
        annotations:
          summary: "High memory usage"
```

#### Integration with PagerDuty/Slack

```typescript
// src/monitoring/alerting.ts
import axios from 'axios';
import { logger } from '../utils/logger';

export class AlertManager {
  static async sendSlackAlert(message: string, severity: 'info' | 'warning' | 'critical') {
    const colors = {
      info: '#36a64f',
      warning: '#ff9900',
      critical: '#ff0000'
    };

    try {
      await axios.post(process.env.SLACK_WEBHOOK_URL, {
        attachments: [{
          color: colors[severity],
          title: `API Alert - ${severity.toUpperCase()}`,
          text: message,
          timestamp: Math.floor(Date.now() / 1000)
        }]
      });
    } catch (error) {
      logger.error('Failed to send Slack alert', { error });
    }
  }

  static async sendPagerDutyAlert(incident: {
    summary: string;
    severity: string;
    source: string;
  }) {
    try {
      await axios.post('https://events.pagerduty.com/v2/enqueue', {
        routing_key: process.env.PAGERDUTY_ROUTING_KEY,
        event_action: 'trigger',
        payload: {
          summary: incident.summary,
          severity: incident.severity,
          source: incident.source,
          timestamp: new Date().toISOString()
        }
      });
    } catch (error) {
      logger.error('Failed to send PagerDuty alert', { error });
    }
  }
}
```

### Database Performance Monitoring

```typescript
// src/monitoring/database.ts
import { PrismaClient } from '@prisma/client';
import { databaseQueryDuration } from './metrics';
import { logger } from '../utils/logger';

export const prisma = new PrismaClient({
  log: [
    { emit: 'event', level: 'query' },
    { emit: 'event', level: 'error' },
    { emit: 'event', level: 'warn' }
  ]
});

// Monitor query performance
prisma.$on('query', (e) => {
  const duration = e.duration / 1000; // Convert to seconds

  databaseQueryDuration.observe(
    { operation: e.query.split(' ')[0], table: 'unknown' },
    duration
  );

  // Log slow queries
  if (duration > 1) {
    logger.warn('Slow database query detected', {
      query: e.query,
      duration,
      params: e.params
    });
  }
});

prisma.$on('error', (e) => {
  logger.error('Database error', { error: e });
});
```

### Uptime Monitoring

Use external services to monitor API availability:

```typescript
// src/monitoring/uptime.ts
import axios from 'axios';

export class UptimeMonitor {
  private endpoints: string[];
  private interval: number;

  constructor(endpoints: string[], intervalMinutes: number = 5) {
    this.endpoints = endpoints;
    this.interval = intervalMinutes * 60 * 1000;
  }

  start() {
    setInterval(() => this.checkEndpoints(), this.interval);
  }

  private async checkEndpoints() {
    for (const endpoint of this.endpoints) {
      try {
        const start = Date.now();
        const response = await axios.get(endpoint, { timeout: 10000 });
        const duration = Date.now() - start;

        logger.info('Uptime check successful', {
          endpoint,
          status: response.status,
          duration
        });
      } catch (error) {
        logger.error('Uptime check failed', {
          endpoint,
          error: error.message
        });

        // Trigger alert
        await AlertManager.sendSlackAlert(
          `Endpoint ${endpoint} is down: ${error.message}`,
          'critical'
        );
      }
    }
  }
}
```

