### 5.4 OAuth 2.0 Integration (Google Example)

**src/services/oauth.service.js:**
```javascript
const { OAuth2Client } = require('google-auth-library');
const config = require('../config/environment');
const User = require('../models/user.model');
const authService = require('./auth.service');
const ApiError = require('../utils/ApiError');

class OAuthService {
  constructor() {
    this.googleClient = new OAuth2Client(
      config.oauth.google.clientId,
      config.oauth.google.clientSecret,
      config.oauth.google.redirectUri
    );
  }

  /**
   * Verify Google token and login/register user
   */
  async googleAuth(idToken) {
    try {
      // Verify token
      const ticket = await this.googleClient.verifyIdToken({
        idToken,
        audience: config.oauth.google.clientId,
      });

      const payload = ticket.getPayload();
      const { email, given_name, family_name, picture } = payload;

      // Check if user exists
      let user = await User.findByEmail(email);

      if (!user) {
        // Create new user
        user = await User.create({
          email,
          first_name: given_name,
          last_name: family_name,
          password: crypto.randomBytes(32).toString('hex'), // Random password
          email_verified: true,
          profile_picture: picture,
        });
      }

      // Generate tokens
      const accessToken = authService.generateAccessToken(user.id, user.email, user.role);
      const refreshToken = authService.generateRefreshToken();

      // Store refresh token
      await RefreshToken.create({
        user_id: user.id,
        token: refreshToken,
        expires_at: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
      });

      return {
        user: User.sanitize(user),
        accessToken,
        refreshToken,
      };
    } catch (error) {
      throw new ApiError(401, 'Invalid Google token');
    }
  }
}

module.exports = new OAuthService();
```

### 5.5 Two-Factor Authentication (2FA)

**src/services/twoFactor.service.js:**
```javascript
const speakeasy = require('speakeasy');
const QRCode = require('qrcode');
const User = require('../models/user.model');
const ApiError = require('../utils/ApiError');

class TwoFactorService {
  /**
   * Generate 2FA secret
   */
  async generateSecret(userId) {
    const user = await User.findById(userId);

    if (!user) {
      throw new ApiError(404, 'User not found');
    }

    const secret = speakeasy.generateSecret({
      name: `ProductionAPI (${user.email})`,
      length: 32,
    });

    // Store secret temporarily (not enabled yet)
    await User.update(userId, {
      two_factor_temp_secret: secret.base32,
    });

    // Generate QR code
    const qrCodeUrl = await QRCode.toDataURL(secret.otpauth_url);

    return {
      secret: secret.base32,
      qrCode: qrCodeUrl,
    };
  }

  /**
   * Enable 2FA
   */
  async enable(userId, token) {
    const user = await User.findById(userId);

    if (!user || !user.two_factor_temp_secret) {
      throw new ApiError(400, 'No pending 2FA setup');
    }

    // Verify token
    const verified = speakeasy.totp.verify({
      secret: user.two_factor_temp_secret,
      encoding: 'base32',
      token,
      window: 2,
    });

    if (!verified) {
      throw new ApiError(400, 'Invalid verification code');
    }

    // Enable 2FA
    await User.update(userId, {
      two_factor_secret: user.two_factor_temp_secret,
      two_factor_enabled: true,
      two_factor_temp_secret: null,
    });

    return { message: '2FA enabled successfully' };
  }

  /**
   * Verify 2FA token
   */
  async verify(userId, token) {
    const user = await User.findById(userId);

    if (!user || !user.two_factor_enabled) {
      throw new ApiError(400, '2FA not enabled');
    }

    const verified = speakeasy.totp.verify({
      secret: user.two_factor_secret,
      encoding: 'base32',
      token,
      window: 2,
    });

    if (!verified) {
      throw new ApiError(401, 'Invalid 2FA code');
    }

    return true;
  }

  /**
   * Disable 2FA
   */
  async disable(userId, password) {
    const user = await User.findById(userId);

    if (!user) {
      throw new ApiError(404, 'User not found');
    }

    // Verify password
    const isPasswordValid = await User.verifyPassword(password, user.password);
    if (!isPasswordValid) {
      throw new ApiError(401, 'Invalid password');
    }

    // Disable 2FA
    await User.update(userId, {
      two_factor_enabled: false,
      two_factor_secret: null,
    });

    return { message: '2FA disabled successfully' };
  }
}

module.exports = new TwoFactorService();
```

