## 10.10 Uptime Monitoring

Use external services to monitor API availability.

```typescript
// src/services/uptimeMonitoring.ts
import axios from 'axios';
import { logger } from '../config/logger';

export class UptimeMonitor {
  private endpoints: string[];
  private interval: number;
  private timerId?: NodeJS.Timeout;

  constructor(endpoints: string[], intervalMinutes: number = 5) {
    this.endpoints = endpoints;
    this.interval = intervalMinutes * 60 * 1000;
  }

  start() {
    this.timerId = setInterval(() => this.checkEndpoints(), this.interval);
    logger.info('Uptime monitoring started');
  }

  stop() {
    if (this.timerId) {
      clearInterval(this.timerId);
      logger.info('Uptime monitoring stopped');
    }
  }

  private async checkEndpoints() {
    for (const endpoint of this.endpoints) {
      try {
        const start = Date.now();
        const response = await axios.get(endpoint, { timeout: 10000 });
        const duration = Date.now() - start;

        logger.info('Uptime check successful', {
          endpoint,
          status: response.status,
          duration: `${duration}ms`,
        });

        // Track metric
        if (process.env.MONITORING_WEBHOOK) {
          await this.reportMetric(endpoint, true, duration);
        }
      } catch (error) {
        logger.error('Uptime check failed', {
          endpoint,
          error: error instanceof Error ? error.message : 'Unknown error',
        });

        // Send alert
        await this.sendAlert(endpoint, error);
      }
    }
  }

  private async reportMetric(endpoint: string, success: boolean, duration: number) {
    try {
      await axios.post(process.env.MONITORING_WEBHOOK!, {
        endpoint,
        success,
        duration,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      logger.error('Failed to report uptime metric', { error });
    }
  }

  private async sendAlert(endpoint: string, error: any) {
    if (process.env.ALERT_WEBHOOK) {
      try {
        await axios.post(process.env.ALERT_WEBHOOK, {
          type: 'uptime_failure',
          endpoint,
          error: error instanceof Error ? error.message : 'Unknown error',
          timestamp: new Date().toISOString(),
        });
      } catch (alertError) {
        logger.error('Failed to send uptime alert', { alertError });
      }
    }
  }
}
```

## 10.11 Complete Monitoring Setup

Integrate all monitoring components into your application.

```typescript
// src/app.ts (updated with monitoring)
import express from 'express';
import { initErrorTracking, sentryRequestHandler, sentryTracingHandler, sentryErrorHandler } from './config/errorTracking';
import { metricsMiddleware, metricsEndpoint } from './middleware/metrics.middleware';
import { httpLogger, logger } from './config/logger';
import healthRoutes from './routes/health.routes';
import monitoringRoutes from './routes/monitoring.routes';
import { prisma } from './config/database';
import { prismaMonitoringMiddleware } from './config/monitoring';

const app = express();

// Initialize error tracking (must be first)
initErrorTracking(app);
app.use(sentryRequestHandler);
app.use(sentryTracingHandler);

// Logging middleware
app.use(httpLogger);

// Metrics middleware
app.use(metricsMiddleware);

// Body parsing
app.use(express.json());

// Health check routes (no auth required)
app.use('/api', healthRoutes);

// Metrics endpoint (for Prometheus)
app.get('/metrics', metricsEndpoint);

// Protected monitoring routes
app.use('/api', monitoringRoutes);

// Your other routes...
// app.use('/api/v1', routes);

// Sentry error handler (must be before other error handlers)
app.use(sentryErrorHandler);

// Your error handling middleware
// app.use(errorHandler);

// Add Prisma monitoring middleware
prisma.$use(prismaMonitoringMiddleware);

// Graceful shutdown
process.on('SIGTERM', async () => {
  logger.info('SIGTERM received, shutting down gracefully');

  // Close database connections
  await prisma.$disconnect();

  // Close server
  process.exit(0);
});

export default app;
```

## 10.12 Docker Compose with Monitoring Stack

Complete monitoring stack with Prometheus and Grafana.

```yaml
# docker-compose.monitoring.yml
version: '3.8'

services:
  api:
    build: .
    ports:
      - "3000:3000"
    environment:
      - NODE_ENV=production
      - DATABASE_URL=postgresql://user:password@postgres:5432/mydb
      - SENTRY_DSN=${SENTRY_DSN}
      - NEW_RELIC_LICENSE_KEY=${NEW_RELIC_LICENSE_KEY}
    depends_on:
      - postgres
      - redis
    networks:
      - monitoring

  prometheus:
    image: prom/prometheus:latest
    ports:
      - "9090:9090"
    volumes:
      - ./prometheus.yml:/etc/prometheus/prometheus.yml
      - ./alerting-rules.yml:/etc/prometheus/alerting-rules.yml
      - prometheus-data:/prometheus
    command:
      - '--config.file=/etc/prometheus/prometheus.yml'
      - '--storage.tsdb.path=/prometheus'
    networks:
      - monitoring

  grafana:
    image: grafana/grafana:latest
    ports:
      - "3001:3000"
    environment:
      - GF_SECURITY_ADMIN_PASSWORD=admin
      - GF_USERS_ALLOW_SIGN_UP=false
    volumes:
      - grafana-data:/var/lib/grafana
      - ./grafana-dashboard.json:/etc/grafana/provisioning/dashboards/api-dashboard.json
    depends_on:
      - prometheus
    networks:
      - monitoring

  alertmanager:
    image: prom/alertmanager:latest
    ports:
      - "9093:9093"
    volumes:
      - ./alertmanager.yml:/etc/alertmanager/alertmanager.yml
    command:
      - '--config.file=/etc/alertmanager/alertmanager.yml'
    networks:
      - monitoring

  postgres:
    image: postgres:15
    environment:
      - POSTGRES_USER=user
      - POSTGRES_PASSWORD=password
      - POSTGRES_DB=mydb
    volumes:
      - postgres-data:/var/lib/postgresql/data
    networks:
      - monitoring

  redis:
    image: redis:7-alpine
    networks:
      - monitoring

volumes:
  prometheus-data:
  grafana-data:
  postgres-data:

networks:
  monitoring:
    driver: bridge
```

```yaml
# prometheus.yml
global:
  scrape_interval: 15s
  evaluation_interval: 15s

alerting:
  alertmanagers:
    - static_configs:
        - targets: ['alertmanager:9093']

rule_files:
  - '/etc/prometheus/alerting-rules.yml'

scrape_configs:
  - job_name: 'api'
    static_configs:
      - targets: ['api:3000']
    metrics_path: '/metrics'

  - job_name: 'prometheus'
    static_configs:
      - targets: ['localhost:9090']
```

## 10.13 Monitoring Best Practices

1. **Monitor the Four Golden Signals**:
   - **Latency**: Response time of requests
   - **Traffic**: Number of requests
   - **Errors**: Rate of failed requests
   - **Saturation**: Resource utilization

2. **Set Meaningful Alerts**:
   - Alert on symptoms, not causes
   - Avoid alert fatigue with proper thresholds
   - Include actionable information in alerts

3. **Use Structured Logging**:
   - Include context (user ID, request ID, etc.)
   - Use consistent log levels
   - Make logs searchable

4. **Track Business Metrics**:
   - User signups, logins, purchases
   - Feature usage
   - Conversion rates

5. **Monitor Dependencies**:
   - Database performance
   - External API calls
   - Cache hit rates

6. **Implement Distributed Tracing**:
   - Track requests across services
   - Identify bottlenecks in microservices

7. **Regular Review**:
   - Review dashboards weekly
   - Update alerts based on patterns
   - Archive unused metrics

8. **Security Monitoring**:
   - Failed authentication attempts
   - Unusual traffic patterns
   - Rate limit violations

## 10.14 Summary

Effective monitoring provides:
- **Visibility**: Real-time insight into application health
- **Reliability**: Early detection of issues
- **Performance**: Identification of bottlenecks
- **Security**: Detection of suspicious activity
- **Compliance**: Audit trails and SLA tracking

With comprehensive monitoring in place, your REST API is now production-ready with full observability across all layers—from infrastructure to application to business metrics.

