    const { refreshToken } = req.body;
    const userAgent = req.get('user-agent');
    const ipAddress = req.ip;

    const result = await authService.refreshAccessToken(
      refreshToken,
      userAgent,
      ipAddress
    );

    res.status(200).json(
      new ApiResponse(200, result, 'Token refreshed successfully')
    );
  });

  /**
