### 5.3 OAuth Integration (Optional)

**src/services/oauth.service.js:**
```javascript
const axios = require('axios');
const config = require('../config/environment');
const userModel = require('../models/user.model');
const authService = require('./auth.service');
const ApiError = require('../utils/ApiError');

class OAuthService {
  /**
   * Google OAuth login
   */
  async googleLogin(code, userAgent, ipAddress) {
    // Exchange code for tokens
    const tokenResponse = await axios.post(
      'https://oauth2.googleapis.com/token',
      {
        code,
        client_id: config.oauth.google.clientId,
        client_secret: config.oauth.google.clientSecret,
        redirect_uri: config.oauth.google.redirectUri,
        grant_type: 'authorization_code',
      }
    );

    const { access_token } = tokenResponse.data;

    // Get user info
    const userInfoResponse = await axios.get(
      'https://www.googleapis.com/oauth2/v2/userinfo',
      {
        headers: { Authorization: `Bearer ${access_token}` },
      }
    );

    const { email, name, picture } = userInfoResponse.data;

    // Find or create user
    let user = await userModel.findByEmail(email);

    if (!user) {
      user = await userModel.create({
        email,
        username: email.split('@')[0],
        firstName: name.split(' ')[0],
        lastName: name.split(' ').slice(1).join(' '),
        avatar: picture,
        isEmailVerified: true,
        password: crypto.randomBytes(32).toString('hex'), // Random password
      });
    }

    // Generate tokens
    const tokens = await authService.generateTokenPair(
      user.id,
      userAgent,
      ipAddress
    );

    return {
      user: userModel.sanitizeUser(user),
      tokens,
    };
  }

  /**
   * GitHub OAuth login
   */
  async githubLogin(code, userAgent, ipAddress) {
    // Similar implementation for GitHub
    // ...
  }
}

module.exports = new OAuthService();
```

