Monitoring is essential for maintaining a production-ready REST API. It provides visibility into your application's health, performance, and user experience, enabling you to detect and resolve issues before they impact users. This section builds on all previous sections to create a comprehensive monitoring strategy.

### 10.1 The Three Pillars of Observability

**Metrics** - Numerical measurements over time (CPU usage, request rate, response time)
**Logs** - Discrete events with context (errors, user actions, system events)
**Traces** - Request flow through distributed systems

### 10.2 Health Check Endpoints

Building on Section 2's routing and Section 4's database setup, create health check endpoints:

```javascript
// routes/health.js
const express = require('express');
const router = express.Router();
const pool = require('../config/database'); // From Section 4

// Basic health check
router.get('/health', (req, res) => {
  res.status(200).json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
    environment: process.env.NODE_ENV
  });
});

// Detailed readiness check
router.get('/health/ready', async (req, res) => {
  const checks = {
    database: false,
    memory: false,
    disk: false
  };

  try {
    // Database check (from Section 4)
    const dbResult = await pool.query('SELECT 1');
    checks.database = dbResult.rows.length > 0;

    // Memory check
    const memUsage = process.memoryUsage();
    const memThreshold = 0.9; // 90% threshold
    checks.memory = (memUsage.heapUsed / memUsage.heapTotal) < memThreshold;

    // All checks passed
    const allHealthy = Object.values(checks).every(check => check === true);

    res.status(allHealthy ? 200 : 503).json({
      status: allHealthy ? 'ready' : 'not ready',
      checks,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    res.status(503).json({
      status: 'not ready',
      checks,
      error: error.message,
      timestamp: new Date().toISOString()
    });
  }
});

// Liveness check
router.get('/health/live', (req, res) => {
  res.status(200).json({
    status: 'alive',
    timestamp: new Date().toISOString()
  });
});

module.exports = router;
```

### 10.3 Structured Logging with Winston

Enhance the error handling from Section 7 with comprehensive logging:

```javascript
// config/logger.js
const winston = require('winston');
const path = require('path');

// Define log format
const logFormat = winston.format.combine(
  winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
  winston.format.errors({ stack: true }),
  winston.format.splat(),
  winston.format.json()
);

// Create logger instance
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: logFormat,
  defaultMeta: { 
    service: 'rest-api',
    environment: process.env.NODE_ENV 
  },
  transports: [
    // Error logs
    new winston.transports.File({ 
      filename: path.join('logs', 'error.log'), 
      level: 'error',
      maxsize: 5242880, // 5MB
      maxFiles: 5
    }),
    // Combined logs
    new winston.transports.File({ 
      filename: path.join('logs', 'combined.log'),
      maxsize: 5242880,
      maxFiles: 5
    })
  ]
});

// Console logging for development
if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.combine(
      winston.format.colorize(),
      winston.format.simple()
    )
  }));
}

module.exports = logger;
```

**Request Logging Middleware** (builds on Section 3):

```javascript
// middleware/requestLogger.js
const logger = require('../config/logger');

const requestLogger = (req, res, next) => {
  const startTime = Date.now();

  // Log request
  logger.info('Incoming request', {
    method: req.method,
    url: req.url,
    ip: req.ip,
    userAgent: req.get('user-agent'),
    userId: req.user?.id // From Section 5's authentication
  });

  // Capture response
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    const logLevel = res.statusCode >= 400 ? 'warn' : 'info';

    logger[logLevel]('Request completed', {
      method: req.method,
      url: req.url,
      statusCode: res.statusCode,
      duration: `${duration}ms`,
      userId: req.user?.id
    });
  });

  next();
};

module.exports = requestLogger;
```

### 10.4 Error Tracking with Sentry

Integrate Sentry with the error handling from Section 7:

```javascript
// config/sentry.js
const Sentry = require('@sentry/node');
const Tracing = require('@sentry/tracing');

const initSentry = (app) => {
  if (process.env.NODE_ENV === 'production') {
    Sentry.init({
      dsn: process.env.SENTRY_DSN,
      environment: process.env.NODE_ENV,
      integrations: [
        new Sentry.Integrations.Http({ tracing: true }),
        new Tracing.Integrations.Express({ app })
      ],
      tracesSampleRate: 0.1, // 10% of transactions
      beforeSend(event, hint) {
        // Filter sensitive data
        if (event.request) {
          delete event.request.cookies;
          delete event.request.headers?.authorization;
        }
        return event;
      }
    });
  }
};

module.exports = { initSentry, Sentry };
```

**Update server.js** (from Section 1):

```javascript
// server.js
const express = require('express');
const { initSentry, Sentry } = require('./config/sentry');
const logger = require('./config/logger');
const requestLogger = require('./middleware/requestLogger');

const app = express();

// Initialize Sentry (must be first)
initSentry(app);

// Sentry request handler
app.use(Sentry.Handlers.requestHandler());
app.use(Sentry.Handlers.tracingHandler());

// Request logging
app.use(requestLogger);

// ... other middleware from Section 3

// Routes from Section 2
app.use('/api/v1', require('./routes'));
app.use('/health', require('./routes/health'));

// Sentry error handler (before other error handlers)
app.use(Sentry.Handlers.errorHandler());

// Error handling middleware from Section 7
app.use(require('./middleware/errorHandler'));

// Start server
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  logger.info(`Server running on port ${PORT}`);
});
```

### 10.5 Custom Metrics with Prometheus

Track application metrics for monitoring dashboards:

```javascript
// config/metrics.js
const promClient = require('prom-client');

// Create a Registry
const register = new promClient.Registry();

// Add default metrics (CPU, memory, etc.)
promClient.collectDefaultMetrics({ register });

// Custom metrics
const httpRequestDuration = new promClient.Histogram({
  name: 'http_request_duration_seconds',
  help: 'Duration of HTTP requests in seconds',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.1, 0.5, 1, 2, 5]
});

const httpRequestTotal = new promClient.Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code']
});

const activeConnections = new promClient.Gauge({
  name: 'active_connections',
  help: 'Number of active connections'
});

const databaseQueryDuration = new promClient.Histogram({
  name: 'database_query_duration_seconds',
  help: 'Duration of database queries',
  labelNames: ['operation', 'table'],
  buckets: [0.01, 0.05, 0.1, 0.5, 1]
});

const authenticationAttempts = new promClient.Counter({
  name: 'authentication_attempts_total',
  help: 'Total authentication attempts',
  labelNames: ['status'] // success, failure
});

const validationErrors = new promClient.Counter({
  name: 'validation_errors_total',
  help: 'Total validation errors',
  labelNames: ['field']
});

// Register metrics
register.registerMetric(httpRequestDuration);
register.registerMetric(httpRequestTotal);
register.registerMetric(activeConnections);
register.registerMetric(databaseQueryDuration);
register.registerMetric(authenticationAttempts);
register.registerMetric(validationErrors);

module.exports = {
  register,
  httpRequestDuration,
  httpRequestTotal,
  activeConnections,
  databaseQueryDuration,
  authenticationAttempts,
  validationErrors
};
```

**Metrics Middleware** (builds on Section 3):

```javascript
// middleware/metricsMiddleware.js
const { httpRequestDuration, httpRequestTotal, activeConnections } = require('../config/metrics');

const metricsMiddleware = (req, res, next) => {
  const startTime = Date.now();
  activeConnections.inc();

  res.on('finish', () => {
    const duration = (Date.now() - startTime) / 1000;
    const route = req.route?.path || req.path;
    const labels = {
      method: req.method,
      route,
      status_code: res.statusCode
    };

    httpRequestDuration.observe(labels, duration);
    httpRequestTotal.inc(labels);
    activeConnections.dec();
  });

  next();
};

module.exports = metricsMiddleware;
```

**Metrics Endpoint**:

```javascript
// routes/metrics.js
const express = require('express');
const router = express.Router();
const { register } = require('../config/metrics');

router.get('/metrics', async (req, res) => {
  res.set('Content-Type', register.contentType);
  res.end(await register.metrics());
});

module.exports = router;
```

### 10.6 Database Monitoring

Enhance database queries from Section 4 with monitoring:

```javascript
// utils/monitoredQuery.js
const pool = require('../config/database');
const { databaseQueryDuration } = require('../config/metrics');
const logger = require('../config/logger');

const monitoredQuery = async (query, params, operation = 'SELECT', table = 'unknown') => {
  const startTime = Date.now();

  try {
    const result = await pool.query(query, params);
    const duration = (Date.now() - startTime) / 1000;

    // Record metrics
    databaseQueryDuration.observe({ operation, table }, duration);

    // Log slow queries
    if (duration > 1) {
      logger.warn('Slow query detected', {
        query,
        duration: `${duration}s`,
        operation,
        table
      });
    }

    return result;
  } catch (error) {
    logger.error('Database query error', {
      query,
      error: error.message,
      operation,
      table
    });
    throw error;
  }
};

module.exports = monitoredQuery;
```

### 10.7 Authentication Monitoring

Track authentication metrics from Section 5:

```javascript
// middleware/auth.js (enhanced)
const jwt = require('jsonwebtoken');
const { authenticationAttempts } = require('../config/metrics');
const logger = require('../config/logger');

const authenticate = async (req, res, next) => {
  try {
    const token = req.headers.authorization?.split(' ')[1];

    if (!token) {
      authenticationAttempts.inc({ status: 'missing_token' });
      return res.status(401).json({ error: 'No token provided' });
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;

    authenticationAttempts.inc({ status: 'success' });
    next();
  } catch (error) {
    authenticationAttempts.inc({ status: 'failure' });

    logger.warn('Authentication failure', {
      error: error.message,
      ip: req.ip,
      userAgent: req.get('user-agent')
    });

    res.status(401).json({ error: 'Invalid token' });
  }
};

module.exports = authenticate;
```

### 10.8 Validation Error Monitoring

Track validation errors from Section 6:

```javascript
// middleware/validate.js (enhanced)
const { validationErrors } = require('../config/metrics');
const logger = require('../config/logger');

const validate = (schema) => {
  return (req, res, next) => {
    const { error } = schema.validate(req.body, { abortEarly: false });

    if (error) {
      // Track validation errors
      error.details.forEach(detail => {
        validationErrors.inc({ field: detail.path.join('.') });
      });

      logger.info('Validation error', {
        errors: error.details.map(d => ({
          field: d.path.join('.'),
          message: d.message
        })),
        endpoint: req.path
      });

      return res.status(400).json({
        error: 'Validation failed',
        details: error.details.map(d => ({
          field: d.path.join('.'),
          message: d.message
        }))
      });
    }

    next();
  };
};

module.exports = validate;
```

