const ApiError = require('../utils/ApiError');
const User = require('../models/user.model');
const AuthService = require('./auth.service');

class OAuthService {
  /**
   * Google OAuth login
   */
  static async googleLogin(code) {
    try {
      // Exchange code for tokens
      const tokenResponse = await axios.post('https://oauth2.googleapis.com/token', {
        code,
        client_id: process.env.GOOGLE_CLIENT_ID,
        client_secret: process.env.GOOGLE_CLIENT_SECRET,
        redirect_uri: process.env.GOOGLE_REDIRECT_URI,
        grant_type: 'authorization_code'
      });

      const { access_token } = tokenResponse.data;

      // Get user info
      const userResponse = await axios.get('https://www.googleapis.com/oauth2/v2/userinfo', {
        headers: { Authorization: `Bearer ${access_token}` }
      });

      const { email, given_name, family_name, picture } = userResponse.data;

      // Find or create user
      let user = await User.findByEmail(email);

      if (!user) {
        user = await User.create({
          email,
          firstName: given_name,
          lastName: family_name,
          password: crypto.randomBytes(32).toString('hex'), // Random password
          isEmailVerified: true,
          avatar: picture
        });
      }

      // Generate tokens
      const accessToken = AuthService.generateAccessToken(user.id);
      const refreshToken = AuthService.generateRefreshToken(user.id);

      return {
        user,
        tokens: {
          accessToken,
          refreshToken
        }
      };
    } catch (error) {
      throw new ApiError(400, 'Google authentication failed');
    }
  }

  /**
   * GitHub OAuth login
   */
  static async githubLogin(code) {
    try {
      // Exchange code for access token
      const tokenResponse = await axios.post(
        'https://github.com/login/oauth/access_token',
        {
          client_id: process.env.GITHUB_CLIENT_ID,
          client_secret: process.env.GITHUB_CLIENT_SECRET,
          code
        },
        {
          headers: { Accept: 'application/json' }
        }
      );

      const { access_token } = tokenResponse.data;

      // Get user info
      const userResponse = await axios.get('https://api.github.com/user', {
        headers: { Authorization: `Bearer ${access_token}` }
      });

      const { email, name, avatar_url } = userResponse.data;

      // Find or create user
      let user = await User.findByEmail(email);

      if (!user) {
        const [firstName, ...lastNameParts] = name.split(' ');
        user = await User.create({
          email,
          firstName,
          lastName: lastNameParts.join(' '),
          password: crypto.randomBytes(32).toString('hex'),
          isEmailVerified: true,
          avatar: avatar_url
        });
      }

      // Generate tokens
      const accessToken = AuthService.generateAccessToken(user.id);
      const refreshToken = AuthService.generateRefreshToken(user.id);

      return {
        user,
        tokens: {
          accessToken,
          refreshToken
        }
      };
    } catch (error) {
      throw new ApiError(400, 'GitHub authentication failed');
    }
  }
}

module.exports = OAuthService;
```

### 5.4 Two-Factor Authentication (2FA)

**src/services/twoFactor.service.js:**
```javascript
const speakeasy = require('speakeasy');
const QRCode = require('qrcode');
const User = require('../models/user.model');
const ApiError = require('../utils/ApiError');

class TwoFactorService {
  /**
   * Generate 2FA secret
   */
  static async generateSecret(userId) {
    const user = await User.findById(userId);

    if (!user) {
      throw new ApiError(404, 'User not found');
    }

    const secret = speakeasy.generateSecret({
      name: `ProductionAPI (${user.email})`,
      length: 32
    });

    // Store secret temporarily (not enabled yet)
    await User.update(userId, {
      twoFactorTempSecret: secret.base32
    });

    // Generate QR code
    const qrCodeUrl = await QRCode.toDataURL(secret.otpauth_url);

    return {
      secret: secret.base32,
      qrCode: qrCodeUrl
    };
  }

  /**
   * Enable 2FA
   */
  static async enable(userId, token) {
    const user = await User.findById(userId);

    if (!user || !user.twoFactorTempSecret) {
      throw new ApiError(400, 'No pending 2FA setup');
    }

    // Verify token
    const verified = speakeasy.totp.verify({
      secret: user.twoFactorTempSecret,
      encoding: 'base32',
      token,
      window: 2
    });

    if (!verified) {
      throw new ApiError(400, 'Invalid verification code');
    }

    // Enable 2FA
    await User.update(userId, {
      twoFactorSecret: user.twoFactorTempSecret,
      twoFactorTempSecret: null,
      twoFactorEnabled: true
    });

    // Generate backup codes
    const backupCodes = this.generateBackupCodes();
    await User.update(userId, {
      twoFactorBackupCodes: JSON.stringify(backupCodes)
    });

    return { backupCodes };
  }

  /**
   * Disable 2FA
   */
  static async disable(userId, password) {
    const user = await User.findById(userId);

    if (!user) {
      throw new ApiError(404, 'User not found');
    }

    // Verify password
    const isPasswordValid = await User.verifyPassword(user, password);
    if (!isPasswordValid) {
      throw new ApiError(401, 'Invalid password');
    }

    await User.update(userId, {
      twoFactorSecret: null,
      twoFactorEnabled: false,
      twoFactorBackupCodes: null
    });

    return { message: '2FA disabled successfully' };
  }

  /**
   * Verify 2FA token
   */
  static async verify(userId, token) {
    const user = await User.findById(userId);

    if (!user || !user.twoFactorEnabled) {
      throw new ApiError(400, '2FA not enabled');
    }

    // Try TOTP verification
    const verified = speakeasy.totp.verify({
      secret: user.twoFactorSecret,
      encoding: 'base32',
      token,
      window: 2
    });

    if (verified) {
      return true;
    }

    // Try backup code
    if (user.twoFactorBackupCodes) {
      const backupCodes = JSON.parse(user.twoFactorBackupCodes);
      const codeIndex = backupCodes.indexOf(token);

      if (codeIndex !== -1) {
        // Remove used backup code
        backupCodes.splice(codeIndex, 1);
        await User.update(userId, {
          twoFactorBackupCodes: JSON.stringify(backupCodes)
        });
        return true;
      }
    }

    return false;
  }

  /**
   * Generate backup codes
   */
  static generateBackupCodes(count = 10) {
    const codes = [];
    for (let i = 0; i < count; i++) {
      codes.push(
        crypto.randomBytes(4).toString('hex').toUpperCase()
      );
    }
    return codes;
  }
}

module.exports = TwoFactorService;
```

