## 6. Validation

### 6.1 Request Validation with Joi

**src/validators/auth.validator.js:**
```javascript
const Joi = require('joi');

const password = Joi.string()
  .min(8)
  .max(128)
  .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/)
  .messages({
    'string.pattern.base': 'Password must contain at least one uppercase letter, one lowercase letter, one number, and one special character'
  });

const email = Joi.string()
  .email()
  .lowercase()
  .trim();

exports.register = Joi.object({
  body: Joi.object({
    email: email.required(),
    password: password.required(),
    firstName: Joi.string().min(2).max(50).trim().required(),
    lastName: Joi.string().min(2).max(50).trim().required(),
    role: Joi.string().valid('user', 'admin', 'manager').default('user')
  })
});

exports.login = Joi.object({
  body: Joi.object({
    email: email.required(),
    password: Joi.string().required()
  })
});

exports.refreshToken = Joi.object({
  body: Joi.object({
    refreshToken: Joi.string().required()
  })
});

exports.forgotPassword = Joi.object({
  body: Joi.object({
    email: email.required()
  })
});

exports.resetPassword = Joi.object({
  body: Joi.object({
    token: Joi.string().required(),
    password: password.required()
  })
});

exports.verifyEmail = Joi.object({
  body: Joi.object({
    token: Joi.string().required()
  })
});

exports.changePassword = Joi.object({
  body: Joi.object({
    currentPassword: Joi.string().required(),
    newPassword: password.required()
  })
});
```

