### The Importance of Monitoring

Monitoring is the final critical piece of a production-ready REST API. Without proper monitoring, you're flying blind—unable to detect issues before they impact users, diagnose problems when they occur, or optimize performance based on real-world usage patterns.

A production API needs comprehensive observability across three pillars:
- **Metrics**: Quantitative measurements (response times, error rates, throughput)
- **Logs**: Detailed event records for debugging and auditing
- **Traces**: Request flow tracking across distributed systems

### Monitoring Strategy Overview

Your monitoring stack should answer these key questions:
1. **Is the API up and responding?** (Uptime monitoring)
2. **How fast is it responding?** (Performance metrics)
3. **Are there errors occurring?** (Error tracking)
4. **What's the resource usage?** (Infrastructure monitoring)
5. **What happened when something went wrong?** (Logging and tracing)

### Setting Up Application Metrics

Install the necessary dependencies:

```bash
npm install prom-client express-prom-bundle
npm install winston winston-daily-rotate-file
npm install @sentry/node @sentry/tracing
npm install --save-dev @types/express-prom-bundle
```

Create `src/monitoring/metrics.ts`:

```typescript
import promClient from 'prom-client';

// Enable default metrics (CPU, memory, event loop lag, etc.)
promClient.collectDefaultMetrics({
  timeout: 5000,
  gcDurationBuckets: [0.001, 0.01, 0.1, 1, 2, 5],
});

// Custom metrics
export const httpRequestDuration = new promClient.Histogram({
  name: 'http_request_duration_seconds',
  help: 'Duration of HTTP requests in seconds',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.01, 0.05, 0.1, 0.5, 1, 2, 5],
});

export const httpRequestTotal = new promClient.Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code'],
});

export const activeConnections = new promClient.Gauge({
  name: 'active_connections',
  help: 'Number of active connections',
});

export const databaseQueryDuration = new promClient.Histogram({
  name: 'database_query_duration_seconds',
  help: 'Duration of database queries in seconds',
  labelNames: ['operation', 'model'],
  buckets: [0.001, 0.01, 0.05, 0.1, 0.5, 1],
});

export const authenticationAttempts = new promClient.Counter({
  name: 'authentication_attempts_total',
  help: 'Total number of authentication attempts',
  labelNames: ['status'], // 'success' or 'failure'
});

export const register = promClient.register;
```

### Structured Logging with Winston

Create `src/monitoring/logger.ts`:

```typescript
import winston from 'winston';
import DailyRotateFile from 'winston-daily-rotate-file';
import path from 'path';

const logDir = process.env.LOG_DIR || 'logs';

// Custom format for structured logging
const structuredFormat = winston.format.combine(
  winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
  winston.format.errors({ stack: true }),
  winston.format.metadata(),
  winston.format.json()
);

// Console format for development
const consoleFormat = winston.format.combine(
  winston.format.colorize(),
  winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
  winston.format.printf(({ timestamp, level, message, ...meta }) => {
    let msg = `${timestamp} [${level}]: ${message}`;
    if (Object.keys(meta).length > 0) {
      msg += ` ${JSON.stringify(meta)}`;
    }
    return msg;
  })
);

// Create transports
const transports: winston.transport[] = [
  // Console output
  new winston.transports.Console({
    format: process.env.NODE_ENV === 'production' ? structuredFormat : consoleFormat,
  }),
];

// File transports for production
if (process.env.NODE_ENV === 'production') {
  // Error logs
  transports.push(
    new DailyRotateFile({
      filename: path.join(logDir, 'error-%DATE%.log'),
      datePattern: 'YYYY-MM-DD',
      level: 'error',
      maxFiles: '30d',
      maxSize: '20m',
      format: structuredFormat,
    })
  );

  // Combined logs
  transports.push(
    new DailyRotateFile({
      filename: path.join(logDir, 'combined-%DATE%.log'),
      datePattern: 'YYYY-MM-DD',
      maxFiles: '14d',
      maxSize: '20m',
      format: structuredFormat,
    })
  );

  // Access logs (HTTP requests)
  transports.push(
    new DailyRotateFile({
      filename: path.join(logDir, 'access-%DATE%.log'),
      datePattern: 'YYYY-MM-DD',
      maxFiles: '14d',
      maxSize: '20m',
      format: structuredFormat,
      level: 'http',
    })
  );
}

// Create logger instance
export const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: structuredFormat,
  defaultMeta: {
    service: 'rest-api',
    environment: process.env.NODE_ENV,
  },
  transports,
});

// Add custom log levels for HTTP requests
logger.level = 'http';

// Helper functions for common logging patterns
export const logRequest = (req: any, res: any, duration: number) => {
  logger.http('HTTP Request', {
    method: req.method,
    url: req.url,
    statusCode: res.statusCode,
    duration: `${duration}ms`,
    ip: req.ip,
    userAgent: req.get('user-agent'),
    userId: req.user?.id,
  });
};

export const logError = (error: Error, context?: Record<string, any>) => {
  logger.error('Application Error', {
    message: error.message,
    stack: error.stack,
    ...context,
  });
};

export const logDatabaseQuery = (operation: string, model: string, duration: number) => {
  logger.debug('Database Query', {
    operation,
    model,
    duration: `${duration}ms`,
  });
};

export const logAuthentication = (success: boolean, email: string, reason?: string) => {
  logger.info('Authentication Attempt', {
    success,
    email,
    reason,
  });
};
```

### Monitoring Middleware

Create `src/middleware/monitoring.middleware.ts`:

```typescript
import { Request, Response, NextFunction } from 'express';
import {
  httpRequestDuration,
  httpRequestTotal,
  activeConnections,
} from '../monitoring/metrics';
import { logRequest } from '../monitoring/logger';

export const metricsMiddleware = (
  req: Request,
  res: Response,
  next: NextFunction
) => {
  const start = Date.now();

  // Increment active connections
  activeConnections.inc();

  // Capture response finish event
  res.on('finish', () => {
    const duration = (Date.now() - start) / 1000; // Convert to seconds
    const route = req.route?.path || req.path;
    const statusCode = res.statusCode.toString();

    // Record metrics
    httpRequestDuration
      .labels(req.method, route, statusCode)
      .observe(duration);

    httpRequestTotal
      .labels(req.method, route, statusCode)
      .inc();

    activeConnections.dec();

    // Log the request
    logRequest(req, res, duration * 1000);
  });

  next();
};

// Request ID middleware for tracing
export const requestIdMiddleware = (
  req: Request,
  res: Response,
  next: NextFunction
) => {
  const requestId = req.headers['x-request-id'] as string || 
    `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

  req.requestId = requestId;
  res.setHeader('X-Request-ID', requestId);

  next();
};

// Extend Express Request type
declare global {
  namespace Express {
    interface Request {
      requestId?: string;
    }
  }
}
```

### Error Tracking with Sentry

Create `src/monitoring/sentry.ts`:

```typescript
import * as Sentry from '@sentry/node';
import * as Tracing from '@sentry/tracing';
import { Express } from 'express';

export const initSentry = (app: Express) => {
  if (!process.env.SENTRY_DSN) {
    console.warn('Sentry DSN not configured, error tracking disabled');
    return;
  }

  Sentry.init({
    dsn: process.env.SENTRY_DSN,
    environment: process.env.NODE_ENV,
    integrations: [
      // Enable HTTP calls tracing
      new Sentry.Integrations.Http({ tracing: true }),
      // Enable Express.js middleware tracing
      new Tracing.Integrations.Express({ app }),
    ],
    tracesSampleRate: process.env.NODE_ENV === 'production' ? 0.1 : 1.0,

    // Filter out sensitive data
    beforeSend(event, hint) {
      // Remove sensitive headers
      if (event.request?.headers) {
        delete event.request.headers['authorization'];
        delete event.request.headers['cookie'];
      }

      // Remove sensitive data from request body
      if (event.request?.data) {
        const data = event.request.data as any;
        if (data.password) data.password = '[REDACTED]';
        if (data.token) data.token = '[REDACTED]';
      }

      return event;
    },
  });

  return Sentry;
};

export const sentryRequestHandler = () => Sentry.Handlers.requestHandler();
export const sentryTracingHandler = () => Sentry.Handlers.tracingHandler();
export const sentryErrorHandler = () => Sentry.Handlers.errorHandler();
```

### Health Check Endpoints

Create `src/routes/health.routes.ts`:

```typescript
import { Router, Request, Response } from 'express';
import { prisma } from '../config/database';
import { register } from '../monitoring/metrics';

const router = Router();

// Basic health check
router.get('/health', (req: Request, res: Response) => {
  res.status(200).json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  });
});

// Detailed readiness check
router.get('/ready', async (req: Request, res: Response) => {
  const checks = {
    database: false,
    memory: false,
  };

  try {
    // Check database connection
    await prisma.$queryRaw`SELECT 1`;
    checks.database = true;
  } catch (error) {
    console.error('Database health check failed:', error);
  }

  // Check memory usage
  const memUsage = process.memoryUsage();
  const memUsagePercent = (memUsage.heapUsed / memUsage.heapTotal) * 100;
  checks.memory = memUsagePercent < 90; // Alert if > 90% memory used

  const isReady = checks.database && checks.memory;

  res.status(isReady ? 200 : 503).json({
    status: isReady ? 'ready' : 'not ready',
    checks,
    memory: {
      heapUsed: `${Math.round(memUsage.heapUsed / 1024 / 1024)}MB`,
      heapTotal: `${Math.round(memUsage.heapTotal / 1024 / 1024)}MB`,
      usage: `${memUsagePercent.toFixed(2)}%`,
    },
    timestamp: new Date().toISOString(),
  });
});

// Liveness check (for Kubernetes)
router.get('/live', (req: Request, res: Response) => {
  res.status(200).json({
    status: 'alive',
    timestamp: new Date().toISOString(),
  });
});

// Metrics endpoint for Prometheus
router.get('/metrics', async (req: Request, res: Response) => {
  res.set('Content-Type', register.contentType);
  res.end(await register.metrics());
});

export default router;
```

### Database Query Monitoring

Update `src/config/database.ts` to add query monitoring:

```typescript
import { PrismaClient } from '@prisma/client';
import { databaseQueryDuration } from '../monitoring/metrics';
import { logDatabaseQuery } from '../monitoring/logger';

export const prisma = new PrismaClient({
  log: process.env.NODE_ENV === 'development' 
    ? ['query', 'error', 'warn'] 
    : ['error'],
});

// Middleware to monitor query performance
prisma.$use(async (params, next) => {
  const start = Date.now();

  try {
    const result = await next(params);
    const duration = Date.now() - start;

    // Record metrics
    databaseQueryDuration
      .labels(params.action, params.model || 'unknown')
      .observe(duration / 1000);

    // Log slow queries (> 1 second)
    if (duration > 1000) {
      logDatabaseQuery(params.action, params.model || 'unknown', duration);
    }

    return result;
  } catch (error) {
    const duration = Date.now() - start;
    logDatabaseQuery(params.action, params.model || 'unknown', duration);
    throw error;
  }
});
```

### Enhanced Authentication Monitoring

Update `src/services/auth.service.ts` to add monitoring:

```typescript
import { authenticationAttempts } from '../monitoring/metrics';
import { logAuthentication } from '../monitoring/logger';
import * as Sentry from '@sentry/node';

export class AuthService {
  static async login(email: string, password: string) {
    try {
      const user = await prisma.user.findUnique({
        where: { email },
      });

      if (!user) {
        authenticationAttempts.labels('failure').inc();
        logAuthentication(false, email, 'User not found');
        throw new UnauthorizedError('Invalid credentials');
      }

      const isValidPassword = await bcrypt.compare(password, user.password);

      if (!isValidPassword) {
        authenticationAttempts.labels('failure').inc();
        logAuthentication(false, email, 'Invalid password');
        throw new UnauthorizedError('Invalid credentials');
      }

      authenticationAttempts.labels('success').inc();
      logAuthentication(true, email);

      // Set user context for Sentry
      Sentry.setUser({ id: user.id, email: user.email });

      const accessToken = this.generateAccessToken(user);
      const refreshToken = this.generateRefreshToken(user);

      return { accessToken, refreshToken, user };
    } catch (error) {
      Sentry.captureException(error);
      throw error;
    }
  }
}
```

