### 5.3 OAuth 2.0 Integration (Google Example)

**src/services/oauth.service.js:**
```javascript
const { OAuth2Client } = require('google-auth-library');
const config = require('../config/environment');
const User = require('../models/user.model');
const AuthService = require('./auth.service');
const ApiError = require('../utils/ApiError');

class OAuthService {
  constructor() {
    this.googleClient = new OAuth2Client(
      process.env.GOOGLE_CLIENT_ID,
      process.env.GOOGLE_CLIENT_SECRET,
      process.env.GOOGLE_REDIRECT_URI
    );
  }

  /**
   * Verify Google ID token
   */
  async verifyGoogleToken(idToken) {
    try {
      const ticket = await this.googleClient.verifyIdToken({
        idToken,
        audience: process.env.GOOGLE_CLIENT_ID,
      });

      return ticket.getPayload();
    } catch (error) {
      throw new ApiError(401, 'Invalid Google token');
    }
  }

  /**
   * Login or register with Google
   */
  async googleAuth(idToken, req) {
    const payload = await this.verifyGoogleToken(idToken);

    const { email, given_name, family_name, email_verified } = payload;

    // Check if user exists
    let user = await User.findByEmail(email);

    if (!user) {
      // Create new user
      user = await User.create({
        email: email.toLowerCase(),
        first_name: given_name,
        last_name: family_name,
        password: crypto.randomBytes(32).toString('hex'), // Random password
        is_email_verified: email_verified,
        oauth_provider: 'google',
        oauth_id: payload.sub,
      });
    }

    // Generate tokens
    const tokens = await AuthService.generateTokens(user.id, req);

    return {
      user: User.sanitize(user),
      tokens,
    };
  }
}

module.exports = new OAuthService();
```

### 5.4 Two-Factor Authentication (2FA)

**src/services/twoFactor.service.js:**
```javascript
const speakeasy = require('speakeasy');
const QRCode = require('qrcode');
const User = require('../models/user.model');
const ApiError = require('../utils/ApiError');

class TwoFactorService {
  /**
   * Generate 2FA secret
   */
  async generateSecret(userId) {
    const user = await User.findById(userId);

    const secret = speakeasy.generateSecret({
      name: `YourApp (${user.email})`,
      length: 32,
    });

    // Store secret temporarily (not enabled yet)
    await User.update(userId, {
      two_factor_temp_secret: secret.base32,
    });

    // Generate QR code
    const qrCodeUrl = await QRCode.toDataURL(secret.otpauth_url);

    return {
      secret: secret.base32,
      qrCode: qrCodeUrl,
    };
  }

  /**
   * Enable 2FA
   */
  async enable(userId, token) {
    const user = await User.findById(userId);

    if (!user.two_factor_temp_secret) {
      throw new ApiError(400, 'No 2FA setup in progress');
    }

    // Verify token
    const verified = speakeasy.totp.verify({
      secret: user.two_factor_temp_secret,
      encoding: 'base32',
      token,
      window: 2,
    });

    if (!verified) {
      throw new ApiError(400, 'Invalid verification code');
    }

    // Enable 2FA
    await User.update(userId, {
      two_factor_secret: user.two_factor_temp_secret,
      two_factor_temp_secret: null,
      two_factor_enabled: true,
    });

    // Generate backup codes
    const backupCodes = this.generateBackupCodes();
    await this.storeBackupCodes(userId, backupCodes);

    return { backupCodes };
  }

  /**
   * Verify 2FA token
   */
  async verify(userId, token) {
    const user = await User.findById(userId);

    if (!user.two_factor_enabled) {
      throw new ApiError(400, '2FA is not enabled');
    }

    // Try regular token
    const verified = speakeasy.totp.verify({
      secret: user.two_factor_secret,
      encoding: 'base32',
      token,
      window: 2,
    });

    if (verified) {
      return true;
    }

    // Try backup code
    const backupCodeValid = await this.verifyBackupCode(userId, token);
    return backupCodeValid;
  }

  /**
   * Disable 2FA
   */
  async disable(userId, password) {
    const user = await User.findById(userId);

    const isPasswordValid = await User.comparePassword(password, user.password);
    if (!isPasswordValid) {
      throw new ApiError(401, 'Invalid password');
    }

    await User.update(userId, {
      two_factor_secret: null,
      two_factor_enabled: false,
    });

    await this.deleteBackupCodes(userId);
  }

  /**
   * Generate backup codes
   */
  generateBackupCodes(count = 10) {
    const codes = [];
    for (let i = 0; i < count; i++) {
      codes.push(crypto.randomBytes(4).toString('hex'));
    }
    return codes;
  }

  /**
   * Store backup codes
   */
  async storeBackupCodes(userId, codes) {
    const hashedCodes = await Promise.all(
      codes.map(code => bcrypt.hash(code, 10))
    );

    await db('two_factor_backup_codes').insert(
      hashedCodes.map(hash => ({
        user_id: userId,
        code: hash,
      }))
    );
  }

  /**
   * Verify backup code
   */
  async verifyBackupCode(userId, code) {
    const backupCodes = await db('two_factor_backup_codes')
      .where({ user_id: userId, used: false });

    for (const backupCode of backupCodes) {
      const isValid = await bcrypt.compare(code, backupCode.code);
      if (isValid) {
        // Mark as used
        await db('two_factor_backup_codes')
          .where({ id: backupCode.id })
          .update({ used: true });
        return true;
      }
    }

    return false;
  }

  /**
   * Delete backup codes
   */
  async deleteBackupCodes(userId) {
    await db('two_factor_backup_codes')
      .where({ user_id: userId })
      .del();
  }
}

module.exports = new TwoFactorService();
```

