### Alerting System

Create `src/services/alert.service.ts`:

```typescript
import logger from '@/utils/logger';
import nodemailer from 'nodemailer';
import axios from 'axios';

export interface Alert {
  severity: 'info' | 'warning' | 'critical';
  title: string;
  message: string;
  metadata?: Record<string, any>;
}

export class AlertService {
  private emailTransporter: nodemailer.Transporter;

  constructor() {
    this.emailTransporter = nodemailer.createTransport({
      host: process.env.SMTP_HOST,
      port: parseInt(process.env.SMTP_PORT || '587'),
      secure: false,
      auth: {
        user: process.env.SMTP_USER,
        pass: process.env.SMTP_PASS
      }
    });
  }

  async sendAlert(alert: Alert): Promise<void> {
    logger.warn('Alert triggered', alert);

    // Send to multiple channels based on severity
    const promises: Promise<any>[] = [];

    if (alert.severity === 'critical') {
      promises.push(this.sendEmail(alert));
      promises.push(this.sendSlack(alert));
      promises.push(this.sendPagerDuty(alert));
    } else if (alert.severity === 'warning') {
      promises.push(this.sendSlack(alert));
    }

    await Promise.allSettled(promises);
  }

  private async sendEmail(alert: Alert): Promise<void> {
    try {
      await this.emailTransporter.sendMail({
        from: process.env.ALERT_EMAIL_FROM,
        to: process.env.ALERT_EMAIL_TO,
        subject: `[${alert.severity.toUpperCase()}] ${alert.title}`,
        html: `
          <h2>${alert.title}</h2>
          <p><strong>Severity:</strong> ${alert.severity}</p>
          <p><strong>Message:</strong> ${alert.message}</p>
          ${alert.metadata ? `<pre>${JSON.stringify(alert.metadata, null, 2)}</pre>` : ''}
          <p><em>Timestamp: ${new Date().toISOString()}</em></p>
        `
      });
    } catch (error) {
      logger.error('Failed to send email alert', { error });
    }
  }

  private async sendSlack(alert: Alert): Promise<void> {
    try {
      const color = {
        info: '#36a64f',
        warning: '#ff9900',
        critical: '#ff0000'
      }[alert.severity];

      await axios.post(process.env.SLACK_WEBHOOK_URL!, {
        attachments: [{
          color,
          title: alert.title,
          text: alert.message,
          fields: alert.metadata ? Object.entries(alert.metadata).map(([key, value]) => ({
            title: key,
            value: String(value),
            short: true
          })) : [],
          footer: 'API Monitoring',
          ts: Math.floor(Date.now() / 1000)
        }]
      });
    } catch (error) {
      logger.error('Failed to send Slack alert', { error });
    }
  }

  private async sendPagerDuty(alert: Alert): Promise<void> {
    try {
      await axios.post('https://events.pagerduty.com/v2/enqueue', {
        routing_key: process.env.PAGERDUTY_ROUTING_KEY,
        event_action: 'trigger',
        payload: {
          summary: alert.title,
          severity: alert.severity,
          source: 'api-monitoring',
          custom_details: alert.metadata
        }
      });
    } catch (error) {
      logger.error('Failed to send PagerDuty alert', { error });
    }
  }
}
