### Overview

Monitoring is the final critical piece of a production-ready REST API. After deploying your API (Section 9), you need visibility into its health, performance, and user behavior. Effective monitoring enables you to detect issues before users report them, optimize performance, and make data-driven decisions.

This section integrates monitoring across all layers built in previous sections: project setup (1), routing (2), middleware (3), database (4), authentication (5), validation (6), error handling (7), testing (8), and deployment (9).

---

### The Three Pillars of Observability

**1. Metrics** - Numerical measurements over time (response times, request counts, error rates)  
**2. Logs** - Discrete events with context (errors, warnings, info)  
**3. Traces** - Request flow through distributed systems

---

### Setting Up Application Monitoring

#### Install Monitoring Dependencies

```bash
npm install prom-client express-prom-bundle
npm install winston winston-daily-rotate-file
npm install @sentry/node @sentry/tracing
npm install @opentelemetry/api @opentelemetry/sdk-node
npm install newrelic  # Optional: for New Relic APM
```

---

### 1. Metrics with Prometheus

#### Configure Prometheus Metrics Middleware

```typescript
// src/middleware/metrics.ts
import promBundle from 'express-prom-bundle';
import { Counter, Histogram, Gauge, register } from 'prom-client';

// Create custom metrics
export const httpRequestDuration = new Histogram({
  name: 'http_request_duration_seconds',
  help: 'Duration of HTTP requests in seconds',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.1, 0.5, 1, 2, 5, 10]
});

export const httpRequestTotal = new Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code']
});

export const activeConnections = new Gauge({
  name: 'active_connections',
  help: 'Number of active connections'
});

export const databaseQueryDuration = new Histogram({
  name: 'database_query_duration_seconds',
  help: 'Duration of database queries',
  labelNames: ['operation', 'table'],
  buckets: [0.01, 0.05, 0.1, 0.5, 1, 2]
});

export const authenticationAttempts = new Counter({
  name: 'authentication_attempts_total',
  help: 'Total authentication attempts',
  labelNames: ['status', 'method'] // success/failure, jwt/oauth
});

export const validationErrors = new Counter({
  name: 'validation_errors_total',
  help: 'Total validation errors',
  labelNames: ['endpoint', 'field']
});

// Prometheus middleware bundle
export const metricsMiddleware = promBundle({
  includeMethod: true,
  includePath: true,
  includeStatusCode: true,
  includeUp: true,
  customLabels: { app: 'rest-api' },
  promClient: { collectDefaultMetrics: {} }
});

// Metrics endpoint
export const metricsEndpoint = async (req, res) => {
  res.set('Content-Type', register.contentType);
  res.end(await register.metrics());
};
```

#### Integrate Metrics into App

```typescript
// src/app.ts
import express from 'express';
import { metricsMiddleware, metricsEndpoint, activeConnections } from './middleware/metrics';

const app = express();

// Metrics middleware (early in the chain)
app.use(metricsMiddleware);

// Track active connections
app.use((req, res, next) => {
  activeConnections.inc();
  res.on('finish', () => activeConnections.dec());
  next();
});

// Metrics endpoint
app.get('/metrics', metricsEndpoint);

// ... rest of your middleware and routes
```

#### Add Metrics to Database Layer

```typescript
// src/models/user.model.ts
import { databaseQueryDuration } from '../middleware/metrics';

export class UserModel {
  static async findById(id: string) {
    const end = databaseQueryDuration.startTimer({ 
      operation: 'select', 
      table: 'users' 
    });

    try {
      const user = await prisma.user.findUnique({ where: { id } });
      return user;
    } finally {
      end();
    }
  }

  static async create(data: CreateUserDto) {
    const end = databaseQueryDuration.startTimer({ 
      operation: 'insert', 
      table: 'users' 
    });

    try {
      const user = await prisma.user.create({ data });
      return user;
    } finally {
      end();
    }
  }
}
```

#### Add Metrics to Authentication

```typescript
// src/middleware/auth.ts
import { authenticationAttempts } from './metrics';

export const login = async (req, res, next) => {
  try {
    const { email, password } = req.body;
    const user = await UserModel.findByEmail(email);

    if (!user || !(await bcrypt.compare(password, user.password))) {
      authenticationAttempts.inc({ status: 'failure', method: 'jwt' });
      throw new UnauthorizedError('Invalid credentials');
    }

    authenticationAttempts.inc({ status: 'success', method: 'jwt' });
    const token = generateToken(user);
    res.json({ token });
  } catch (error) {
    next(error);
  }
};
```

#### Add Metrics to Validation

```typescript
// src/middleware/validation.ts
import { validationErrors } from './metrics';

export const validate = (schema: Joi.Schema) => {
  return (req, res, next) => {
    const { error } = schema.validate(req.body, { abortEarly: false });

    if (error) {
      error.details.forEach(detail => {
        validationErrors.inc({ 
          endpoint: req.path, 
          field: detail.path.join('.') 
        });
      });

      throw new ValidationError(error.details);
    }

    next();
  };
};
```

