## 6. Validation

### 6.1 Request Validation Schemas

**src/validators/auth.validator.js:**
```javascript
const Joi = require('joi');

const password = Joi.string()
  .min(8)
  .max(128)
  .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/)
  .required()
  .messages({
    'string.pattern.base':
      'Password must contain at least one uppercase letter, one lowercase letter, one number, and one special character',
    'string.min': 'Password must be at least 8 characters long',
  });

exports.register = {
  body: Joi.object({
    email: Joi.string().email().required().messages({
      'string.email': 'Please provide a valid email address',
      'any.required': 'Email is required',
    }),
    username: Joi.string()
      .alphanum()
      .min(3)
      .max(30)
      .required()
      .messages({
        'string.alphanum': 'Username must only contain alphanumeric characters',
        'string.min': 'Username must be at least 3 characters long',
        'string.max': 'Username cannot exceed 30 characters',
      }),
    password,
    confirmPassword: Joi.string()
      .valid(Joi.ref('password'))
      .required()
      .messages({
        'any.only': 'Passwords do not match',
      }),
    firstName: Joi.string().max(100).optional(),
    lastName: Joi.string().max(100).optional(),
    phone: Joi.string()
      .pattern(/^\+?[1-9]\d{1,14}$/)
      .optional()
      .messages({
        'string.pattern.base': 'Please provide a valid phone number',
      }),
  }),
};

exports.login = {
  body: Joi.object({
    email: Joi.string().email().required(),
    password: Joi.string().required(),
  }),
};

exports.refreshToken = {
  body: Joi.object({
    refreshToken: Joi.string().optional(),
  }),
};

exports.forgotPassword = {
  body: Joi.object({
    email: Joi.string().email().required(),
  }),
};

exports.resetPassword = {
  params: Joi.object({
    token: Joi.string().required(),
  }),
  body: Joi.object({
    password,
    confirmPassword: Joi.string()
      .valid(Joi.ref('password'))
      .required()
      .messages({
        'any.only': 'Passwords do not match',
      }),
  }),
};

exports.verifyEmail = {
  body: Joi.object({
    token: Joi.string().required(),
  }),
};
```

**src/validators/user.validator.js:**
```javascript
const Joi = require('joi');

exports.getUsers = {
  query: Joi.object({
    page: Joi.number().integer().min(1).default(1),
    limit: Joi.number().integer().min(1).max(100).default(10),
    sort: Joi.string()
      .valid('createdAt', '-createdAt', 'email', '-email', 'username', '-username')
      .default('-createdAt'),
    search: Joi.string().max(100).optional(),
    role: Joi.string().valid('user', 'admin', 'seller').optional(),
    isActive: Joi.boolean().optional(),
  }),
};

exports.getUserById = {
  params: Joi.object({
    id: Joi.string().uuid().required().messages({
      'string.guid': 'Invalid user ID format',
    }),
  }),
};

exports.createUser = {
  body: Joi.object({
    email: Joi.string().email().required(),
    username: Joi.string().alphanum().min(3).max(30).required(),
    password: Joi.string()
      .min(8)
      .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/)
      .required(),
    firstName: Joi.string().max(100).optional(),
    lastName: Joi.string().max(100).optional(),
    phone: Joi.string().pattern(/^\+?[1-9]\d{1,14}$/).optional(),
    role: Joi.string().valid('user', 'admin', 'seller').default('user'),
  }),
};

exports.updateUser = {
  params: Joi.object({
    id: Joi.string().uuid().required(),
  }),
  body: Joi.object({
    email: Joi.string().email().optional(),
    username: Joi.string().alphanum().min(3).max(30).optional(),
    firstName: Joi.string().max(100).optional(),
    lastName: Joi.string().max(100).optional(),
    phone: Joi.string().pattern(/^\+?[1-9]\d{1,14}$/).optional(),
    role: Joi.string().valid('user', 'admin', 'seller').optional(),
    isActive: Joi.boolean().optional(),
  }).min(1),
};

exports.deleteUser = {
  params: Joi.object({
    id: Joi.string().uuid().required(),
  }),
};

exports.updateMyProfile = {
  body: Joi.object({
    firstName: Joi.string().max(100).optional(),
    lastName: Joi.string().max(100).optional(),
    phone: Joi.string().pattern(/^\+?[1-9]\d{1,14}$/).optional(),
  }).min(1),
};
