const Joi = require('joi');

exports.getProducts = {
  query: Joi.object({
    page: Joi.number().integer().min(1).default(1),
    limit: Joi.number().integer().min(1).max(100).default(10),
    sort: Joi.string()
      .valid(
        'createdAt',
        '-createdAt',
        'price',
        '-price',
        'name',
        '-name'
      )
      .default('-createdAt'),
    search: Joi.string().max(100).optional(),
    categoryId: Joi.string().uuid().optional(),
    minPrice: Joi.number().min(0).optional(),
    maxPrice: Joi.number().min(0).optional(),
    isActive: Joi.boolean().optional(),
    isFeatured: Joi.boolean().optional(),
  }),
};

exports.getProductById = {
  params: Joi.object({
    id: Joi.string().uuid().required(),
  }),
};

exports.createProduct = {
  body: Joi.object({
    name: Joi.string().max(255).required(),
    slug: Joi.string().max(255).required(),
    description: Joi.string().optional(),
    price: Joi.number().positive().precision(2).required(),
    compareAtPrice: Joi.number().positive().precision(2).optional(),
    quantity: Joi.number().integer().min(0).default(0),
    sku: Joi.string().max(100).optional(),
    categoryId: Joi.string().uuid().optional(),
    images: Joi.array().items(Joi.string().uri()).optional(),
    attributes: Joi.object().optional(),
    isActive: Joi.boolean().default(true),
    isFeatured: Joi.boolean().default(false),
  }),
};

exports.updateProduct = {
  params: Joi.object({
    id: Joi.string().uuid().required(),
  }),
  body: Joi.object({
    name: Joi.string().max(255).optional(),
    slug: Joi.string().max(255).optional(),
    description: Joi.string().optional(),
    price: Joi.number().positive().precision(2).optional(),
    compareAtPrice: Joi.number().positive().precision(2).optional(),
    quantity: Joi.number().integer().min(0).optional(),
    sku: Joi.string().max(100).optional(),
    categoryId: Joi.string().uuid().optional(),
    images: Joi.array().items(Joi.string().uri()).optional(),
    attributes: Joi.object().optional(),
    isActive: Joi.boolean().optional(),
    isFeatured: Joi.boolean().optional(),
  }).min(1),
};

exports.deleteProduct = {
  params: Joi.object({
    id: Joi.string().uuid().required(),
  }),
};

exports.getProductReviews = {
  params: Joi.object({
    id: Joi.string().uuid().required(),
  }),
  query: Joi.object({
    page: Joi.number().integer().min(1).default(1),
    limit: Joi.number().integer().min(1).max(100).default(10),
  }),
};

exports.createProductReview = {
  params: Joi.object({
    id: Joi.string().uuid().required(),
  }),
  body: Joi.object({
    rating: Joi.number().integer().min(1).max(5).required(),
    comment: Joi.string().max(1000).required(),
  }),
};
```

### 6.2 Custom Validation Rules

**src/validators/custom.validator.js:**
```javascript
const Joi = require('joi');
const User = require('../models/user.model');
const Product = require('../models/product.model');

/**
 * Custom validator to check if email is unique
 */
exports.uniqueEmail = Joi.string()
  .email()
  .external(async (value) => {
    const user = await User.findByEmail(value);
    if (user) {
      throw new Error('Email already exists');
    }
    return value;
  });

/**
 * Custom validator to check if username is unique
 */
exports.uniqueUsername = Joi.string()
  .external(async (value) => {
    const user = await User.findByUsername(value);
    if (user) {
      throw new Error('Username already exists');
    }
    return value;
  });

/**
 * Custom validator to check if product slug is unique
 */
exports.uniqueSlug = Joi.string()
  .external(async (value, helpers) => {
    const product = await Product.findBySlug(value);

    // Allow same slug if updating the same product
    const productId = helpers.prefs.context?.productId;
    if (product && product.id !== productId) {
      throw new Error('Slug already exists');
    }

    return value;
  });

/**
 * Custom validator for date ranges
 */
exports.dateRange = Joi.object({
  startDate: Joi.date().iso().required(),
  endDate: Joi.date().iso().min(Joi.ref('startDate')).required(),
});

/**
 * Custom validator for file uploads
 */
