## 2. Error Tracking with Sentry

Sentry provides real-time error tracking and alerting:

### Install Sentry

```bash
npm install @sentry/node @sentry/tracing
```

### Configure Sentry

```javascript
// src/utils/sentry.js
const Sentry = require('@sentry/node');
const Tracing = require('@sentry/tracing');

const initSentry = (app) => {
  if (process.env.NODE_ENV === 'production') {
    Sentry.init({
      dsn: process.env.SENTRY_DSN,
      environment: process.env.NODE_ENV,
      integrations: [
        new Sentry.Integrations.Http({ tracing: true }),
        new Tracing.Integrations.Express({ app }),
      ],
      tracesSampleRate: 0.1, // 10% of transactions
    });
  }
};

module.exports = { initSentry, Sentry };
```

### Integrate in App

```javascript
// src/app.js
const express = require('express');
const { initSentry, Sentry } = require('./utils/sentry');

const app = express();

// Initialize Sentry FIRST
initSentry(app);

// Sentry request handler must be first middleware
app.use(Sentry.Handlers.requestHandler());
app.use(Sentry.Handlers.tracingHandler());

// ... other middleware (from Sections 3, 5, 6)
app.use(express.json());
app.use(requestLogger);

// ... routes (from Section 2)
app.use('/api/v1/users', userRoutes);
app.use('/api/v1/products', productRoutes);

// Sentry error handler must be before other error handlers
app.use(Sentry.Handlers.errorHandler());

// Your custom error handler (from Section 7)
app.use(errorHandler);

module.exports = app;
```

### Capture Custom Events

```javascript
// In your route handlers
const { Sentry } = require('../utils/sentry');

exports.createOrder = async (req, res, next) => {
  try {
    const order = await Order.create(req.body);

    // Track important business events
    Sentry.captureMessage('Order created', {
      level: 'info',
      tags: {
        orderId: order.id,
        userId: req.user.id,
        amount: order.total,
      },
    });

    res.status(201).json({ order });
  } catch (error) {
    // Sentry automatically captures errors
    next(error);
  }
};
```

