## 4. Health Check Endpoints

Essential for load balancers and monitoring systems:

```javascript
// src/routes/health.js
const express = require('express');
const mongoose = require('mongoose');
const { Pool } = require('pg'); // If using PostgreSQL

const router = express.Router();

// Basic health check
router.get('/health', (req, res) => {
  res.status(200).json({
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  });
});

// Detailed health check with dependencies
router.get('/health/detailed', async (req, res) => {
  const health = {
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
    checks: {},
  };

  // Check database connection
  try {
    if (mongoose.connection.readyState === 1) {
      health.checks.database = { status: 'ok' };
    } else {
      health.checks.database = { status: 'error', message: 'Not connected' };
      health.status = 'degraded';
    }
  } catch (error) {
    health.checks.database = { status: 'error', message: error.message };
    health.status = 'error';
  }

  // Check memory usage
  const memUsage = process.memoryUsage();
  const memUsageMB = {
    rss: Math.round(memUsage.rss / 1024 / 1024),
    heapTotal: Math.round(memUsage.heapTotal / 1024 / 1024),
    heapUsed: Math.round(memUsage.heapUsed / 1024 / 1024),
  };

  health.checks.memory = {
    status: memUsageMB.heapUsed < 500 ? 'ok' : 'warning',
    usage: memUsageMB,
  };

  const statusCode = health.status === 'ok' ? 200 : 503;
  res.status(statusCode).json(health);
});

// Readiness probe (for Kubernetes)
router.get('/ready', async (req, res) => {
  // Check if app is ready to serve traffic
  if (mongoose.connection.readyState === 1) {
    res.status(200).json({ ready: true });
  } else {
    res.status(503).json({ ready: false });
  }
});

// Liveness probe (for Kubernetes)
router.get('/live', (req, res) => {
  // Simple check that app is running
  res.status(200).json({ alive: true });
});

module.exports = router;
```

