## 6. Database Monitoring

Monitor database performance from Section 4:

```javascript
// src/utils/metrics.js - add database metrics
const { databaseQueryDuration } = require('./metrics');

// Mongoose middleware for MongoDB
const monitorMongooseQueries = () => {
  mongoose.plugin((schema) => {
    schema.pre(/^find/, function() {
      this._startTime = Date.now();
    });

    schema.post(/^find/, function() {
      if (this._startTime) {
        const duration = (Date.now() - this._startTime) / 1000;
        databaseQueryDuration
          .labels('find', this.mongooseCollection.name)
          .observe(duration);
      }
    });
  });
};

