### 5.2 Authentication Controller

**src/controllers/auth.controller.js**
```javascript
const authService = require('../services/auth.service');
const catchAsync = require('../utils/catchAsync');
const ApiResponse = require('../utils/ApiResponse');

/**
 * Register new user
 */
exports.register = catchAsync(async (req, res) => {
  const user = await authService.register(req.body);

  res.status(201).json(
    new ApiResponse(
      201,
      { user },
      'Registration successful. Please verify your email.'
    )
  );
});

/**
 * Login user
 */
exports.login = catchAsync(async (req, res) => {
  const { email, password } = req.body;

  const result = await authService.login(email, password, req);

  // Set refresh token in HTTP-only cookie
  res.cookie('refreshToken', result.refreshToken, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
  });

  res.status(200).json(
    new ApiResponse(
      200,
      {
        user: result.user,
        accessToken: result.accessToken,
      },
      'Login successful'
    )
  );
});

/**
 * Logout user
 */
exports.logout = catchAsync(async (req, res) => {
  const refreshToken = req.cookies.refreshToken || req.body.refreshToken;

  await authService.logout(refreshToken);

  res.clearCookie('refreshToken');

  res.status(200).json(
    new ApiResponse(200, null, 'Logout successful')
  );
});

/**
 * Refresh access token
 */
exports.refreshToken = catchAsync(async (req, res) => {
  const refreshToken = req.cookies.refreshToken || req.body.refreshToken;

  if (!refreshToken) {
    throw new ApiError(401, 'Refresh token required');
  }

  const result = await authService.refreshAccessToken(refreshToken);

  res.status(200).json(
    new ApiResponse(
      200,
      {
        accessToken: result.accessToken,
        user: result.user,
      },
      'Token refreshed successfully'
    )
  );
});

/**
 * Verify email
 */
exports.verifyEmail = catchAsync(async (req, res) => {
  const { token } = req.params;

  const user = await authService.verifyEmail(token);

  res.status(200).json(
    new ApiResponse(200, { user }, 'Email verified successfully')
  );
});

/**
 * Forgot password
 */
exports.forgotPassword = catchAsync(async (req, res) => {
  const { email } = req.body;

  await authService.forgotPassword(email);

  res.status(200).json(
    new ApiResponse(
      200,
      null,
      'If the email exists, a password reset link has been sent'
    )
  );
});

/**
 * Reset password
 */
exports.resetPassword = catchAsync(async (req, res) => {
  const { token, password } = req.body;

  await authService.resetPassword(token, password);

  res.status(200).json(
    new ApiResponse(200, null, 'Password reset successful')
  );
});

/**
 * Change password
 */
exports.changePassword = catchAsync(async (req, res) => {
  const { currentPassword, newPassword } = req.body;

  await authService.changePassword(req.user.id, currentPassword, newPassword);

  res.status(200).json(
    new ApiResponse(200, null, 'Password changed successfully')
  );
});
```

### 5.3 OAuth Integration (Example with Google)

**src/services/oauth.service.js**
```javascript
const { OAuth2Client } = require('google-auth-library');
const config = require('../config/environment');
const User = require('../models/user.model');
const authService = require('./auth.service');
const ApiError = require('../utils/ApiError');

const googleClient = new OAuth2Client(config.google.clientId);

class OAuthService {
  /**
   * Verify Google token and login/register user
   */
  static async googleLogin(token, req) {
    try {
      // Verify token
      const ticket = await googleClient.verifyIdToken({
        idToken: token,
        audience: config.google.clientId,
      });

      const payload = ticket.getPayload();

      // Check if user exists
      let user = await User.findByEmail(payload.email);

      if (!user) {
        // Register new user
        user = await User.create({
          email: payload.email,
          username: payload.email.split('@')[0],
          firstName: payload.given_name,
          lastName: payload.family_name,
          avatar: payload.picture,
          isEmailVerified: payload.email_verified,
          password: crypto.randomBytes(32).toString('hex'), // Random password
        });
      }

      // Generate tokens
      const accessToken = authService.generateAccessToken(user.id);
      const refreshToken = authService.generateRefreshToken(user.id);

      await authService.storeRefreshToken(user.id, refreshToken, req);

      return {
        user: User.sanitize(user),
        accessToken,
        refreshToken,
      };
    } catch (error) {
      throw new ApiError(401, 'Invalid Google token');
    }
  }
}

module.exports = OAuthService;
```

