### 6.1 Request Validation Schemas

**src/validators/auth.validator.js**
```javascript
const Joi = require('joi');

const password = Joi.string()
  .min(8)
  .max(128)
  .pattern(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]/)
  .message(
    'Password must contain at least one uppercase letter, one lowercase letter, one number, and one special character'
  );

const email = Joi.string().email().lowercase().trim();

exports.register = Joi.object({
  body: Joi.object({
    email: email.required(),
    username: Joi.string()
      .alphanum()
      .min(3)
      .max(30)
      .lowercase()
      .trim()
      .required(),
    password: password.required(),
    confirmPassword: Joi.string()
      .valid(Joi.ref('password'))
      .required()
      .messages({
        'any.only': 'Passwords must match',
      }),
    firstName: Joi.string().min(1).max(100).trim(),
    lastName: Joi.string().min(1).max(100).trim(),
    phone: Joi.string().pattern(/^\+?[1-9]\d{1,14}$/),
  }),
});

exports.login = Joi.object({
  body: Joi.object({
    email: email.required(),
    password: Joi.string().required(),
  }),
});

exports.refreshToken = Joi.object({
  body: Joi.object({
    refreshToken: Joi.string(),
  }),
});

exports.forgotPassword = Joi.object({
  body: Joi.object({
    email: email.required(),
  }),
});

exports.resetPassword = Joi.object({
  body: Joi.object({
    token: Joi.string().required(),
    password: password.required(),
    confirmPassword: Joi.string()
      .valid(Joi.ref('password'))
      .required()
      .messages({
        'any.only': 'Passwords must match',
      }),
  }),
});

exports.changePassword = Joi.object({
  body: Joi.object({
    currentPassword: Joi.string().required(),
    newPassword: password.required(),
    confirmPassword: Joi.string()
      .valid(Joi.ref('newPassword'))
      .required()
      .messages({
        'any.only': 'Passwords must match',
      }),
  }),
});
