### Overview
After deploying your REST API (Section 9), monitoring is essential for maintaining reliability, performance, and security in production. Effective monitoring provides visibility into system health, enables proactive issue detection, and supports data-driven optimization decisions.

### 10.1 Monitoring Strategy

A comprehensive monitoring strategy includes four key pillars:

**1. Metrics**: Quantitative measurements (response times, error rates, throughput)
**2. Logs**: Detailed event records for debugging and auditing
**3. Traces**: Request flow tracking across distributed systems
**4. Alerts**: Automated notifications for critical issues

### 10.2 Application Performance Monitoring (APM)

Implement APM tools to track application-level metrics:

**Using New Relic:**

```javascript
// server.js
const newrelic = require('newrelic');
const express = require('express');
const app = express();

// Custom transaction naming
app.use((req, res, next) => {
  newrelic.setTransactionName(`${req.method} ${req.route?.path || req.path}`);
  next();
});

// Custom metrics
function recordCustomMetric(name, value) {
  newrelic.recordMetric(name, value);
}

// Track business metrics
app.post('/api/orders', async (req, res) => {
  const startTime = Date.now();
  try {
    const order = await createOrder(req.body);
    const duration = Date.now() - startTime;

    recordCustomMetric('Custom/Orders/Created', 1);
    recordCustomMetric('Custom/Orders/ProcessingTime', duration);

    res.status(201).json(order);
  } catch (error) {
    newrelic.noticeError(error);
    throw error;
  }
});
```

**Using Datadog APM:**

```javascript
// tracer.js
const tracer = require('dd-trace').init({
  service: 'rest-api',
  env: process.env.NODE_ENV,
  version: process.env.APP_VERSION,
  logInjection: true,
  analytics: true
});

module.exports = tracer;

// Use in application
const tracer = require('./tracer');

app.get('/api/users/:id', async (req, res) => {
  const span = tracer.startSpan('get.user');
  span.setTag('user.id', req.params.id);

  try {
    const user = await getUserById(req.params.id);
    span.setTag('http.status_code', 200);
    res.json(user);
  } catch (error) {
    span.setTag('error', true);
    span.setTag('http.status_code', 500);
    throw error;
  } finally {
    span.finish();
  }
});
```

### 10.3 Metrics Collection

Implement custom metrics using Prometheus:

```javascript
// metrics.js
const client = require('prom-client');

// Create a Registry
const register = new client.Registry();

// Add default metrics
client.collectDefaultMetrics({ register });

// Custom metrics
const httpRequestDuration = new client.Histogram({
  name: 'http_request_duration_seconds',
  help: 'Duration of HTTP requests in seconds',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.1, 0.5, 1, 2, 5]
});

const httpRequestTotal = new client.Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code']
});

const activeConnections = new client.Gauge({
  name: 'active_connections',
  help: 'Number of active connections'
});

const databaseQueryDuration = new client.Histogram({
  name: 'database_query_duration_seconds',
  help: 'Duration of database queries',
  labelNames: ['operation', 'table'],
  buckets: [0.01, 0.05, 0.1, 0.5, 1]
});

// Register metrics
register.registerMetric(httpRequestDuration);
register.registerMetric(httpRequestTotal);
register.registerMetric(activeConnections);
register.registerMetric(databaseQueryDuration);

module.exports = {
  register,
  httpRequestDuration,
  httpRequestTotal,
  activeConnections,
  databaseQueryDuration
};
```

**Metrics Middleware:**

```javascript
// middleware/metrics.js
const { httpRequestDuration, httpRequestTotal, activeConnections } = require('../metrics');

function metricsMiddleware(req, res, next) {
  const start = Date.now();

  activeConnections.inc();

  res.on('finish', () => {
    const duration = (Date.now() - start) / 1000;
    const route = req.route?.path || req.path;
    const labels = {
      method: req.method,
      route: route,
      status_code: res.statusCode
    };

    httpRequestDuration.observe(labels, duration);
    httpRequestTotal.inc(labels);
    activeConnections.dec();
  });

  next();
}

// Metrics endpoint
app.use(metricsMiddleware);

app.get('/metrics', async (req, res) => {
  res.set('Content-Type', register.contentType);
  res.end(await register.metrics());
});
```

### 10.4 Structured Logging

Implement structured logging with Winston:

```javascript
// logger.js
const winston = require('winston');
const { ElasticsearchTransport } = require('winston-elasticsearch');

const esTransportOpts = {
  level: 'info',
  clientOpts: { node: process.env.ELASTICSEARCH_URL },
  index: 'api-logs'
};

const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: {
    service: 'rest-api',
    environment: process.env.NODE_ENV,
    version: process.env.APP_VERSION
  },
  transports: [
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      )
    }),
    new winston.transports.File({ 
      filename: 'logs/error.log', 
      level: 'error' 
    }),
    new winston.transports.File({ 
      filename: 'logs/combined.log' 
    }),
    new ElasticsearchTransport(esTransportOpts)
  ]
});

// Request logging middleware
function requestLogger(req, res, next) {
  const start = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - start;
    logger.info('HTTP Request', {
      method: req.method,
      url: req.url,
      status: res.statusCode,
      duration: duration,
      ip: req.ip,
      userAgent: req.get('user-agent'),
      userId: req.user?.id,
      requestId: req.id
    });
  });

  next();
}

module.exports = { logger, requestLogger };
```

### 10.5 Distributed Tracing

Implement distributed tracing with OpenTelemetry:

```javascript
// tracing.js
const { NodeTracerProvider } = require('@opentelemetry/sdk-trace-node');
const { registerInstrumentations } = require('@opentelemetry/instrumentation');
const { HttpInstrumentation } = require('@opentelemetry/instrumentation-http');
const { ExpressInstrumentation } = require('@opentelemetry/instrumentation-express');
const { JaegerExporter } = require('@opentelemetry/exporter-jaeger');
const { Resource } = require('@opentelemetry/resources');
const { SemanticResourceAttributes } = require('@opentelemetry/semantic-conventions');

const provider = new NodeTracerProvider({
  resource: new Resource({
    [SemanticResourceAttributes.SERVICE_NAME]: 'rest-api',
    [SemanticResourceAttributes.SERVICE_VERSION]: process.env.APP_VERSION,
  }),
});

const jaegerExporter = new JaegerExporter({
  endpoint: process.env.JAEGER_ENDPOINT || 'http://localhost:14268/api/traces',
});

provider.addSpanProcessor(
  new BatchSpanProcessor(jaegerExporter)
);

provider.register();

registerInstrumentations({
  instrumentations: [
    new HttpInstrumentation(),
    new ExpressInstrumentation(),
  ],
});

const tracer = provider.getTracer('rest-api-tracer');

module.exports = tracer;
```

### 10.6 Health Checks

Implement comprehensive health check endpoints:

```javascript
// routes/health.js
const express = require('express');
const router = express.Router();
const db = require('../db');
const redis = require('../redis');

// Liveness probe - is the app running?
router.get('/health/live', (req, res) => {
  res.status(200).json({ status: 'ok' });
});

// Readiness probe - is the app ready to serve traffic?
router.get('/health/ready', async (req, res) => {
  const checks = {
    database: false,
    redis: false,
    overall: false
  };

  try {
    // Check database
    await db.query('SELECT 1');
    checks.database = true;

    // Check Redis
    await redis.ping();
    checks.redis = true;

    checks.overall = checks.database && checks.redis;

    const status = checks.overall ? 200 : 503;
    res.status(status).json(checks);
  } catch (error) {
    res.status(503).json({
      ...checks,
      error: error.message
    });
  }
});

// Detailed health check
router.get('/health/detailed', async (req, res) => {
  const health = {
    uptime: process.uptime(),
    timestamp: Date.now(),
    status: 'ok',
    checks: {}
  };

  // Database check
  try {
    const start = Date.now();
    await db.query('SELECT 1');
    health.checks.database = {
      status: 'healthy',
      responseTime: Date.now() - start
    };
  } catch (error) {
    health.checks.database = {
      status: 'unhealthy',
      error: error.message
    };
    health.status = 'degraded';
  }

  // Memory check
  const memUsage = process.memoryUsage();
  health.checks.memory = {
    status: memUsage.heapUsed / memUsage.heapTotal < 0.9 ? 'healthy' : 'warning',
    heapUsed: memUsage.heapUsed,
    heapTotal: memUsage.heapTotal,
    percentage: (memUsage.heapUsed / memUsage.heapTotal * 100).toFixed(2)
  };

  res.json(health);
});

module.exports = router;
```

### 10.7 Alerting

Configure alerts using Prometheus Alertmanager:

```yaml
# prometheus-alerts.yml
groups:
  - name: api_alerts
    interval: 30s
    rules:
      # High error rate
      - alert: HighErrorRate
        expr: |
          rate(http_requests_total{status_code=~"5.."}[5m]) 
          / rate(http_requests_total[5m]) > 0.05
        for: 5m
        labels:
          severity: critical
        annotations:
          summary: "High error rate detected"
          description: "Error rate is {{ $value | humanizePercentage }}"

      # Slow response time
      - alert: SlowResponseTime
        expr: |
          histogram_quantile(0.95, 
            rate(http_request_duration_seconds_bucket[5m])
          ) > 2
        for: 10m
        labels:
          severity: warning
        annotations:
          summary: "95th percentile response time is high"
          description: "P95 latency is {{ $value }}s"

      # High memory usage
      - alert: HighMemoryUsage
        expr: |
          (process_resident_memory_bytes / 
           node_memory_MemTotal_bytes) > 0.9
        for: 5m
        labels:
          severity: warning
        annotations:
          summary: "High memory usage"
          description: "Memory usage is {{ $value | humanizePercentage }}"

      # Database connection issues
      - alert: DatabaseConnectionFailure
        expr: up{job="postgres"} == 0
        for: 1m
        labels:
          severity: critical
        annotations:
          summary: "Database is down"
          description: "Cannot connect to database"
```

**Alertmanager Configuration:**

```yaml
# alertmanager.yml
global:
  resolve_timeout: 5m
  slack_api_url: 'YOUR_SLACK_WEBHOOK_URL'

route:
  group_by: ['alertname', 'cluster']
  group_wait: 10s
  group_interval: 10s
  repeat_interval: 12h
  receiver: 'default'
  routes:
    - match:
        severity: critical
      receiver: 'pagerduty'
      continue: true
    - match:
        severity: warning
      receiver: 'slack'

receivers:
  - name: 'default'
    slack_configs:
      - channel: '#alerts'
        title: 'API Alert'
        text: '{{ range .Alerts }}{{ .Annotations.description }}{{ end }}'

  - name: 'slack'
    slack_configs:
      - channel: '#api-warnings'
        title: '{{ .GroupLabels.alertname }}'
        text: '{{ range .Alerts }}{{ .Annotations.summary }}{{ end }}'

  - name: 'pagerduty'
    pagerduty_configs:
      - service_key: 'YOUR_PAGERDUTY_KEY'
```

### 10.8 Dashboards

Create monitoring dashboards with Grafana:

```json
// grafana-dashboard.json (excerpt)
{
  "dashboard": {
    "title": "REST API Monitoring",
    "panels": [
      {
        "title": "Request Rate",
        "targets": [
          {
            "expr": "rate(http_requests_total[5m])",
            "legendFormat": "{{method}} {{route}}"
          }
        ],
        "type": "graph"
      },
      {
        "title": "Error Rate",
        "targets": [
          {
            "expr": "rate(http_requests_total{status_code=~\"5..\"}[5m])",
            "legendFormat": "5xx errors"
          }
        ],
        "type": "graph"
      },
      {
        "title": "Response Time (P95)",
        "targets": [
          {
            "expr": "histogram_quantile(0.95, rate(http_request_duration_seconds_bucket[5m]))",
            "legendFormat": "{{route}}"
          }
        ],
        "type": "graph"
      },
      {
        "title": "Active Connections",
        "targets": [
          {
            "expr": "active_connections"
          }
        ],
        "type": "stat"
      }
    ]
  }
}
```

