  /**
   * Logout user
   */
  static async logout(refreshTokenString) {
    const refreshToken = await RefreshToken.findByToken(refreshTokenString);

    if (refreshToken) {
      await RefreshToken.revoke(refreshToken.id);
      logger.info(`User logged out: userId ${refreshToken.userId}`);
    }

    return true;
  }

  /**
   * Request password reset
   */
  static async forgotPassword(email) {
    const user = await User.findByEmail(email);

    if (!user) {
      // Don't reveal if user exists
      return true;
    }

    // Generate reset token
    const resetToken = crypto.randomBytes(32).toString('hex');
    const hashedToken = crypto
      .createHash('sha256')
      .update(resetToken)
      .digest('hex');

    // Save reset token
    await User.update(user.id, {
      passwordResetToken: hashedToken,
      passwordResetExpires: new Date(Date.now() + 60 * 60 * 1000) // 1 hour
    });

    // TODO: Send email with reset token
    logger.info(`Password reset requested for: ${email}`);

    return resetToken; // In production, send via email
  }

  /**
   * Reset password
   */
  static async resetPassword(token, newPassword) {
    const hashedToken = crypto
      .createHash('sha256')
      .update(token)
      .digest('hex');

    // Find user with valid reset token
    const user = await User.findByResetToken(hashedToken);

    if (!user) {
      throw new ApiError(400, 'Invalid or expired reset token');
    }

    // Update password
    await User.update(user.id, {
      password: newPassword,
      passwordResetToken: null,
      passwordResetExpires: null,
      passwordChangedAt: new Date()
    });

    // Revoke all refresh tokens
    await RefreshToken.revokeAllForUser(user.id);

    logger.info(`Password reset for user: ${user.email}`);

    return true;
  }

  /**
   * Update password
   */
  static async updatePassword(userId, currentPassword, newPassword) {
    const user = await User.findById(userId);

    if (!user) {
      throw new ApiError(404, 'User not found');
    }

    // Verify current password
    const isPasswordValid = await User.verifyPassword(
      currentPassword,
      user.password
    );

    if (!isPasswordValid) {
      throw new ApiError(401, 'Current password is incorrect');
    }

    // Update password
    await User.update(userId, {
      password: newPassword,
      passwordChangedAt: new Date()
    });

    // Revoke all refresh tokens except current
    await RefreshToken.revokeAllForUser(userId);

    logger.info(`Password updated for user: ${user.email}`);

    return true;
  }
}

module.exports = AuthService;
