### 5.2 Refresh Token Model

**src/models/refreshToken.model.js:**
```javascript
const db = require('../config/database');

class RefreshToken {
  /**
   * Create refresh token
   */
  static async create(tokenData) {
    const [token] = await db('refresh_tokens')
      .insert(tokenData)
      .returning('*');

    return token;
  }

  /**
   * Find token by string
   */
  static async findByToken(token) {
    return db('refresh_tokens')
      .where({ token, isRevoked: false })
      .first();
  }

  /**
   * Revoke token
   */
  static async revoke(id) {
    await db('refresh_tokens')
      .where({ id })
      .update({
        isRevoked: true,
        revokedAt: new Date()
      });
  }

  /**
   * Revoke all tokens for user
   */
  static async revokeAllForUser(userId) {
    await db('refresh_tokens')
      .where({ userId, isRevoked: false })
      .update({
        isRevoked: true,
        revokedAt: new Date()
      });
  }

  /**
   * Clean up expired tokens
   */
  static async cleanupExpired() {
    const result = await db('refresh_tokens')
      .where('expiresAt', '<', new Date())
      .orWhere('isRevoked', true)
      .delete();

    return result;
  }

  /**
   * Get active tokens for user
   */
  static async getActiveTokensForUser(userId) {
    return db('refresh_tokens')
      .where({
        userId,
        isRevoked: false
      })
      .where('expiresAt', '>', new Date())
      .orderBy('createdAt', 'desc');
  }
}

module.exports = RefreshToken;
```

### 5.3 Authentication Controller

**src/controllers/auth.controller.js:**
```javascript
const authService = require('../services/auth.service');
const catchAsync = require('../utils/catchAsync');
const ApiResponse = require('../utils/ApiResponse');

/**
 * Register new user
 */
exports.register = catchAsync(async (req, res) => {
  const userData = {
    ...req.body,
    userAgent: req.headers['user-agent'],
    ipAddress: req.ip
  };

  const result = await authService.register(userData);

  res.status(201).json(
    new ApiResponse(201, result, 'User registered successfully')
  );
});

/**
 * Login user
 */
exports.login = catchAsync(async (req, res) => {
  const credentials = {
    ...req.body,
    userAgent: req.headers['user-agent'],
    ipAddress: req.ip
  };

  const result = await authService.login(credentials);

  res.status(200).json(
    new ApiResponse(200, result, 'Login successful')
  );
});

/**
 * Refresh access token
 */
exports.refreshToken = catchAsync(async (req, res) => {
  const { refreshToken } = req.body;

  const result = await authService.refreshAccessToken(refreshToken);

  res.status(200).json(
    new ApiResponse(200, result, 'Token refreshed successfully')
  );
});

/**
 * Logout user
 */
exports.logout = catchAsync(async (req, res) => {
  const { refreshToken } = req.body;

  await authService.logout(refreshToken);

  res.status(200).json(
    new ApiResponse(200, null, 'Logout successful')
  );
});

/**
 * Forgot password
 */
exports.forgotPassword = catchAsync(async (req, res) => {
  const { email } = req.body;

  await authService.forgotPassword(email);

  res.status(200).json(
    new ApiResponse(
      200,
      null,
      'If the email exists, a password reset link has been sent'
    )
  );
});

/**
 * Reset password
 */
exports.resetPassword = catchAsync(async (req, res) => {
  const { token, password } = req.body;

  await authService.resetPassword(token, password);

  res.status(200).json(
    new ApiResponse(200, null, 'Password reset successful')
  );
});

/**
 * Get current user
 */
exports.getCurrentUser = catchAsync(async (req, res) => {
  res.status(200).json(
    new ApiResponse(200, req.user, 'User retrieved successfully')
  );
});

/**
 * Update password
 */
exports.updatePassword = catchAsync(async (req, res) => {
  const { currentPassword, newPassword } = req.body;

  await authService.updatePassword(
    req.user.id,
    currentPassword,
    newPassword
  );

  res.status(200).json(
    new ApiResponse(200, null, 'Password updated successfully')
  );
});
```

### 5.4 OAuth Integration (Optional)

**src/services/oauth.service.js:**
```javascript
const axios = require('axios');
const User = require('../models/user.model');
const authService = require('./auth.service');
const ApiError = require('../utils/ApiError');

class OAuthService {
  /**
   * Google OAuth login
   */
  static async googleLogin(code) {
    try {
      // Exchange code for tokens
      const tokenResponse = await axios.post(
        'https://oauth2.googleapis.com/token',
        {
          code,
          client_id: process.env.GOOGLE_CLIENT_ID,
          client_secret: process.env.GOOGLE_CLIENT_SECRET,
          redirect_uri: process.env.GOOGLE_REDIRECT_URI,
          grant_type: 'authorization_code'
        }
      );

      const { access_token } = tokenResponse.data;

      // Get user info
      const userResponse = await axios.get(
        'https://www.googleapis.com/oauth2/v2/userinfo',
        {
          headers: { Authorization: `Bearer ${access_token}` }
        }
      );

      const { email, name, picture } = userResponse.data;

      // Find or create user
      let user = await User.findByEmail(email);

      if (!user) {
        user = await User.create({
          email,
          username: email.split('@')[0],
          password: crypto.randomBytes(32).toString('hex'), // Random password
          firstName: name.split(' ')[0],
          lastName: name.split(' ').slice(1).join(' '),
          avatar: picture,
          emailVerified: true,
          isActive: true
        });
      }

      // Generate tokens
      const accessToken = authService.generateAccessToken(user.id);
      const refreshToken = authService.generateRefreshToken();

      return {
        user,
        accessToken,
        refreshToken
      };
    } catch (error) {
      throw new ApiError(400, 'Google authentication failed');
    }
  }
}

module.exports = OAuthService;
```

