### 5.2 Authentication Controller

**src/controllers/auth.controller.js:**
```javascript
const authService = require('../services/auth.service');
const asyncHandler = require('../utils/asyncHandler');
const ApiResponse = require('../utils/ApiResponse');

class AuthController {
  /**
   * Register new user
   */
  register = asyncHandler(async (req, res) => {
    const result = await authService.register(req.body);

    res.status(201).json(
      new ApiResponse(201, result, 'User registered successfully')
    );
  });

  /**
   * Login user
   */
  login = asyncHandler(async (req, res) => {
    const { email, password } = req.body;

    const result = await authService.login(email, password, req);

    // Set refresh token in HTTP-only cookie
    res.cookie('refreshToken', result.refreshToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
    });

    res.status(200).json(
      new ApiResponse(
        200,
        {
          user: result.user,
          accessToken: result.accessToken,
        },
        'Login successful'
      )
    );
  });

  /**
   * Refresh access token
   */
  refreshToken = asyncHandler(async (req, res) => {
    const refreshToken = req.cookies.refreshToken || req.body.refreshToken;

    if (!refreshToken) {
      throw new ApiError(401, 'Refresh token required');
    }

    const result = await authService.refreshToken(refreshToken);

    res.status(200).json(
      new ApiResponse(200, result, 'Token refreshed successfully')
    );
  });

  /**
   * Logout user
   */
  logout = asyncHandler(async (req, res) => {
    const refreshToken = req.cookies.refreshToken || req.body.refreshToken;

    if (refreshToken) {
      await authService.logout(refreshToken);
    }

    res.clearCookie('refreshToken');

    res.status(200).json(
      new ApiResponse(200, null, 'Logout successful')
    );
  });

  /**
   * Request password reset
   */
  forgotPassword = asyncHandler(async (req, res) => {
    const { email } = req.body;

    const result = await authService.forgotPassword(email);

    res.status(200).json(
      new ApiResponse(200, result, 'Password reset email sent')
    );
  });

  /**
   * Reset password
   */
  resetPassword = asyncHandler(async (req, res) => {
    const { token, password } = req.body;

    const result = await authService.resetPassword(token, password);

    res.status(200).json(
      new ApiResponse(200, result, 'Password reset successful')
    );
  });

  /**
   * Get current user
   */
  getCurrentUser = asyncHandler(async (req, res) => {
    res.status(200).json(
      new ApiResponse(200, req.user, 'User retrieved successfully')
    );
  });

  /**
   * Verify email
   */
  verifyEmail = asyncHandler(async (req, res) => {
    const { token } = req.body;

    const result = await authService.verifyEmail(token);

    res.status(200).json(
      new ApiResponse(200, result, 'Email verified successfully')
    );
  });
}

module.exports = new AuthController();
```

### 5.3 OAuth Integration (Optional)

**src/services/oauth.service.js:**
```javascript
const axios = require('axios');
const config = require('../config/environment');
const userModel = require('../models/user.model');
const authService = require('./auth.service');
const ApiError = require('../utils/ApiError');

class OAuthService {
  /**
   * Google OAuth
   */
  async googleAuth(code) {
    try {
      // Exchange code for tokens
      const tokenResponse = await axios.post(
        'https://oauth2.googleapis.com/token',
        {
          code,
          client_id: config.oauth.google.clientId,
          client_secret: config.oauth.google.clientSecret,
          redirect_uri: config.oauth.google.redirectUri,
          grant_type: 'authorization_code',
        }
      );

      const { access_token } = tokenResponse.data;

      // Get user info
      const userResponse = await axios.get(
        'https://www.googleapis.com/oauth2/v2/userinfo',
        {
          headers: { Authorization: `Bearer ${access_token}` },
        }
      );

      const { email, name, picture } = userResponse.data;

      // Find or create user
      let user = await userModel.findByEmail(email);

      if (!user) {
        user = await userModel.create({
          email,
          username: email.split('@')[0],
          firstName: name,
          password: crypto.randomBytes(32).toString('hex'), // Random password
          emailVerified: true,
          isActive: true,
        });
      }

      // Generate tokens
      const accessToken = authService.generateAccessToken(user.id);
      const refreshToken = authService.generateRefreshToken(user.id);

      return {
        user,
        accessToken,
        refreshToken,
      };
    } catch (error) {
      throw new ApiError(400, 'OAuth authentication failed');
    }
  }
}

module.exports = new OAuthService();
```

### 5.4 Two-Factor Authentication (2FA)

**src/services/twoFactor.service.js:**
```javascript
const speakeasy = require('speakeasy');
const QRCode = require('qrcode');
const userModel = require('../models/user.model');
const ApiError = require('../utils/ApiError');

class TwoFactorService {
  /**
   * Generate 2FA secret
   */
  async generateSecret(userId) {
    const user = await userModel.findById(userId);

    if (!user) {
      throw new ApiError(404, 'User not found');
    }

    const secret = speakeasy.generateSecret({
      name: `ProductionAPI (${user.email})`,
      length: 32,
    });

    // Generate QR code
    const qrCodeUrl = await QRCode.toDataURL(secret.otpauth_url);

    // Store secret (encrypted in production)
    await userModel.update(userId, {
      twoFactorSecret: secret.base32,
      twoFactorEnabled: false, // Not enabled until verified
    });

    return {
      secret: secret.base32,
      qrCode: qrCodeUrl,
    };
  }

  /**
   * Verify and enable 2FA
   */
  async enableTwoFactor(userId, token) {
    const user = await userModel.findById(userId);

    if (!user || !user.twoFactorSecret) {
      throw new ApiError(400, '2FA not set up');
    }

    const verified = speakeasy.totp.verify({
      secret: user.twoFactorSecret,
      encoding: 'base32',
      token,
      window: 2,
    });

    if (!verified) {
      throw new ApiError(400, 'Invalid token');
    }

    await userModel.update(userId, {
      twoFactorEnabled: true,
    });

    return { message: '2FA enabled successfully' };
  }

  /**
   * Verify 2FA token
   */
  async verifyToken(userId, token) {
    const user = await userModel.findById(userId);

    if (!user || !user.twoFactorEnabled) {
      throw new ApiError(400, '2FA not enabled');
    }

    const verified = speakeasy.totp.verify({
      secret: user.twoFactorSecret,
      encoding: 'base32',
      token,
      window: 2,
    });

    if (!verified) {
      throw new ApiError(400, 'Invalid token');
    }

    return true;
  }

  /**
   * Disable 2FA
   */
  async disableTwoFactor(userId, token) {
    const verified = await this.verifyToken(userId, token);

    if (!verified) {
      throw new ApiError(400, 'Invalid token');
    }

    await userModel.update(userId, {
      twoFactorEnabled: false,
      twoFactorSecret: null,
    });

    return { message: '2FA disabled successfully' };
  }
}

module.exports = new TwoFactorService();
```

