import express, { Application } from 'express';
import { config } from './config';
import routes from './routes';
import healthRoutes from './routes/health.routes';
import metricsRoutes from './routes/metrics.routes';
import prisma, { disconnectDatabase } from './config/database';
import { errorHandler } from './middleware/errorHandler';
import { requestLogger } from './middleware/requestLogger';
import { metricsMiddleware } from './middleware/metricsMiddleware';
import { initAPM } from './config/apm';
import { initSentry } from './config/sentry';
import logger from './utils/logger';

// Initialize APM and error tracking
initAPM();

const app: Application = express();

initSentry(app);

// Middleware
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(requestLogger);
app.use(metricsMiddleware);

// Health and metrics endpoints
app.use(healthRoutes);
app.use(metricsRoutes);

// API routes
app.use(routes);

// 404 handler
app.use('*', (req, res, next) => {
  next(new NotFoundError(`Route ${req.originalUrl} not found`));
});

// Error handler
app.use(errorHandler);

// Graceful shutdown
const gracefulShutdown = async (signal: string) => {
  logger.info(`${signal} received, shutting down gracefully...`);

  await disconnectDatabase();

  process.exit(0);
};

process.on('SIGINT', () => gracefulShutdown('SIGINT'));
process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));

// Uncaught exception handler
process.on('uncaughtException', (error: Error) => {
  logger.error('Uncaught Exception:', error);
  gracefulShutdown('uncaughtException');
});

// Unhandled rejection handler
process.on('unhandledRejection', (reason: any) => {
  logger.error('Unhandled Rejection:', reason);
  gracefulShutdown('unhandledRejection');
});

app.listen(config.port, () => {
  logger.info(`Server running on port ${config.port} in ${config.nodeEnv} mode`);
});

export default app;
```

### Key Takeaways

- Implement structured logging with appropriate log levels
- Collect application metrics (request rate, response time, errors)
- Expose metrics endpoint for Prometheus scraping
- Create comprehensive health check endpoints
- Integrate APM tools for detailed performance insights
- Set up alerting for critical issues
- Build dashboards for real-time monitoring
- Track custom business metrics relevant to your API
- Implement distributed tracing for microservices
- Monitor database query performance
- Set up log aggregation for centralized analysis
- Profile application performance regularly
- Monitor memory usage and detect leaks
- Track authentication and authorization metrics
- Implement graceful degradation when dependencies fail

---

## Conclusion

Congratulations! You've now built a complete, production-ready REST API with all essential components:

1. **Project Setup**: Solid foundation with TypeScript, proper structure, and configuration
2. **Routing**: RESTful endpoints with clean separation of concerns
3. **Middleware**: Security, logging, rate limiting, and request processing
4. **Database**: Prisma ORM with migrations, repositories, and efficient queries
5. **Authentication**: JWT-based auth with refresh tokens and role-based access
6. **Validation**: Comprehensive input validation with Joi and sanitization
7. **Error Handling**: Centralized error management with custom error classes
8. **Testing**: Unit, integration, and E2E tests with high coverage
9. **Deployment**: Docker containerization and CI/CD pipelines
10. **Monitoring**: Logging, metrics, alerting, and observability

This API is now ready for production use with security, scalability, maintainability, and observability built in from the ground up.

