### 10.1 Why Monitoring Matters

After deploying your REST API (Section 9), monitoring becomes critical for maintaining reliability, performance, and user satisfaction. Monitoring helps you:

- **Detect issues before users do** - Proactive problem identification
- **Understand system behavior** - Performance patterns and trends
- **Debug production problems** - Root cause analysis
- **Optimize resources** - Cost and performance efficiency
- **Meet SLAs** - Track and maintain service level agreements
- **Make data-driven decisions** - Capacity planning and improvements

### 10.2 The Three Pillars of Observability

**Metrics** - Numerical measurements over time
- Response times, throughput, error rates
- CPU, memory, disk usage
- Database query performance

**Logs** - Discrete event records
- Application logs (from Section 7's error handling)
- Access logs
- Audit trails

**Traces** - Request flow through distributed systems
- End-to-end request tracking
- Service dependencies
- Performance bottlenecks

### 10.3 Application Performance Monitoring (APM)

#### Setting Up APM Tools

**Option 1: New Relic**

```javascript
// server.js
require('newrelic');
const express = require('express');
const app = express();

// Your application code...
```

```javascript
// newrelic.js
exports.config = {
  app_name: ['Production REST API'],
  license_key: process.env.NEW_RELIC_LICENSE_KEY,
  logging: {
    level: 'info'
  },
  transaction_tracer: {
    enabled: true,
    transaction_threshold: 'apdex_f',
    record_sql: 'obfuscated'
  },
  error_collector: {
    enabled: true,
    ignore_status_codes: [404]
  }
};
```

**Option 2: Datadog**

```javascript
// server.js
const tracer = require('dd-trace').init({
  hostname: process.env.DD_AGENT_HOST,
  port: process.env.DD_TRACE_AGENT_PORT,
  env: process.env.NODE_ENV,
  service: 'rest-api',
  version: process.env.APP_VERSION,
  logInjection: true
});

const express = require('express');
const app = express();
```

### 10.4 Metrics Collection with Prometheus

#### Installing Prometheus Client

```bash
npm install prom-client
```

#### Implementing Metrics Middleware

```javascript
// middleware/metrics.js
const client = require('prom-client');

// Create a Registry
const register = new client.Registry();

// Add default metrics (CPU, memory, etc.)
client.collectDefaultMetrics({ register });

// Custom metrics
const httpRequestDuration = new client.Histogram({
  name: 'http_request_duration_seconds',
  help: 'Duration of HTTP requests in seconds',
  labelNames: ['method', 'route', 'status_code'],
  buckets: [0.1, 0.5, 1, 2, 5]
});

const httpRequestTotal = new client.Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code']
});

const activeConnections = new client.Gauge({
  name: 'active_connections',
  help: 'Number of active connections'
});

const databaseQueryDuration = new client.Histogram({
  name: 'database_query_duration_seconds',
  help: 'Duration of database queries',
  labelNames: ['operation', 'table'],
  buckets: [0.01, 0.05, 0.1, 0.5, 1]
});

register.registerMetric(httpRequestDuration);
register.registerMetric(httpRequestTotal);
register.registerMetric(activeConnections);
register.registerMetric(databaseQueryDuration);

// Metrics middleware
const metricsMiddleware = (req, res, next) => {
  const start = Date.now();

  activeConnections.inc();

  res.on('finish', () => {
    const duration = (Date.now() - start) / 1000;
    const route = req.route ? req.route.path : req.path;

    httpRequestDuration
      .labels(req.method, route, res.statusCode)
      .observe(duration);

    httpRequestTotal
      .labels(req.method, route, res.statusCode)
      .inc();

    activeConnections.dec();
  });

  next();
};

module.exports = {
  metricsMiddleware,
  register,
  metrics: {
    httpRequestDuration,
    httpRequestTotal,
    activeConnections,
    databaseQueryDuration
  }
};
```

#### Metrics Endpoint

```javascript
// routes/metrics.js
const express = require('express');
const router = express.Router();
const { register } = require('../middleware/metrics');

router.get('/metrics', async (req, res) => {
  res.set('Content-Type', register.contentType);
  res.end(await register.metrics());
});

module.exports = router;
```

#### Using Metrics in Application

```javascript
// server.js
const { metricsMiddleware } = require('./middleware/metrics');

app.use(metricsMiddleware);
app.use('/api/metrics', require('./routes/metrics'));
```

```javascript
// database/pool.js - Track database metrics
const { metrics } = require('../middleware/metrics');

async function query(text, params, operation = 'query', table = 'unknown') {
  const start = Date.now();

  try {
    const result = await pool.query(text, params);
    const duration = (Date.now() - start) / 1000;

    metrics.databaseQueryDuration
      .labels(operation, table)
      .observe(duration);

    return result;
  } catch (error) {
    const duration = (Date.now() - start) / 1000;
    metrics.databaseQueryDuration
      .labels(operation, table)
      .observe(duration);
    throw error;
  }
}
```

### 10.5 Structured Logging with Winston

Building on Section 7's error handling, implement comprehensive logging:

```javascript
// utils/logger.js
const winston = require('winston');
const { format } = winston;

const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: format.combine(
    format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
    format.errors({ stack: true }),
    format.metadata(),
    format.json()
  ),
  defaultMeta: {
    service: 'rest-api',
    environment: process.env.NODE_ENV,
    version: process.env.APP_VERSION
  },
  transports: [
    // Write all logs to console
    new winston.transports.Console({
      format: format.combine(
        format.colorize(),
        format.printf(({ timestamp, level, message, ...meta }) => {
          return `${timestamp} [${level}]: ${message} ${
            Object.keys(meta).length ? JSON.stringify(meta, null, 2) : ''
          }`;
        })
      )
    }),

    // Write errors to error.log
    new winston.transports.File({
      filename: 'logs/error.log',
      level: 'error',
      maxsize: 10485760, // 10MB
      maxFiles: 5
    }),

    // Write all logs to combined.log
    new winston.transports.File({
      filename: 'logs/combined.log',
      maxsize: 10485760,
      maxFiles: 10
    })
  ]
});

// Add request logging middleware
logger.requestLogger = (req, res, next) => {
  const start = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - start;

    logger.info('HTTP Request', {
      method: req.method,
      url: req.url,
      status: res.statusCode,
      duration: `${duration}ms`,
      ip: req.ip,
      userAgent: req.get('user-agent'),
      userId: req.user?.id
    });
  });

  next();
};

module.exports = logger;
```

#### Integrating Logging Throughout the Application

```javascript
// server.js
const logger = require('./utils/logger');

app.use(logger.requestLogger);

// Log application startup
logger.info('Starting REST API', {
  port: PORT,
  environment: process.env.NODE_ENV,
  nodeVersion: process.version
});
```

