// middleware/errorHandler.js - Enhanced with logging
const logger = require('../utils/logger');

function errorHandler(err, req, res, next) {
  logger.error('Application Error', {
    error: {
      message: err.message,
      stack: err.stack,
      statusCode: err.statusCode
    },
    request: {
      method: req.method,
      url: req.url,
      headers: req.headers,
      body: req.body,
      userId: req.user?.id
    }
  });

  // Send response...
}
```

### 10.6 Error Tracking with Sentry

Integrate Sentry for real-time error tracking:

```bash
npm install @sentry/node @sentry/tracing
```

```javascript
// utils/sentry.js
const Sentry = require('@sentry/node');
const Tracing = require('@sentry/tracing');

function initSentry(app) {
  Sentry.init({
    dsn: process.env.SENTRY_DSN,
    environment: process.env.NODE_ENV,
    release: process.env.APP_VERSION,

    integrations: [
      new Sentry.Integrations.Http({ tracing: true }),
      new Tracing.Integrations.Express({ app }),
      new Tracing.Integrations.Postgres()
    ],

    tracesSampleRate: process.env.NODE_ENV === 'production' ? 0.1 : 1.0,

    beforeSend(event, hint) {
      // Filter sensitive data
      if (event.request) {
        delete event.request.cookies;
        if (event.request.headers) {
          delete event.request.headers.authorization;
        }
      }
      return event;
    }
  });

  return {
    requestHandler: Sentry.Handlers.requestHandler(),
    tracingHandler: Sentry.Handlers.tracingHandler(),
    errorHandler: Sentry.Handlers.errorHandler()
  };
}

module.exports = { initSentry, Sentry };
```

```javascript
// server.js
const { initSentry } = require('./utils/sentry');

const sentryHandlers = initSentry(app);

// Must be first middleware
app.use(sentryHandlers.requestHandler);
app.use(sentryHandlers.tracingHandler);

// Routes...

// Must be before other error handlers
app.use(sentryHandlers.errorHandler);
app.use(errorHandler);
```

### 10.7 Health Check Endpoints

Expand on Section 1's basic health check:

```javascript
// routes/health.js
const express = require('express');
const router = express.Router();
const pool = require('../database/pool');
const logger = require('../utils/logger');

// Basic liveness probe
router.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Detailed readiness probe
router.get('/health/ready', async (req, res) => {
  const checks = {
    database: false,
    memory: false,
    uptime: true
  };

  try {
    // Check database connection
    await pool.query('SELECT 1');
    checks.database = true;
  } catch (error) {
    logger.error('Database health check failed', { error: error.message });
  }

  // Check memory usage
  const memUsage = process.memoryUsage();
  const memThreshold = 0.9; // 90%
  checks.memory = (memUsage.heapUsed / memUsage.heapTotal) < memThreshold;

  const allHealthy = Object.values(checks).every(check => check === true);
  const statusCode = allHealthy ? 200 : 503;

  res.status(statusCode).json({
    status: allHealthy ? 'ready' : 'not ready',
    checks,
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
    memory: {
      heapUsed: `${Math.round(memUsage.heapUsed / 1024 / 1024)}MB`,
      heapTotal: `${Math.round(memUsage.heapTotal / 1024 / 1024)}MB`,
      rss: `${Math.round(memUsage.rss / 1024 / 1024)}MB`
    }
  });
});

// Detailed system info (protected endpoint)
router.get('/health/info', authenticateToken, requireRole('admin'), (req, res) => {
  res.json({
    version: process.env.APP_VERSION,
    environment: process.env.NODE_ENV,
    nodeVersion: process.version,
    platform: process.platform,
    uptime: process.uptime(),
    memory: process.memoryUsage(),
    cpu: process.cpuUsage(),
    timestamp: new Date().toISOString()
  });
});

module.exports = router;
```

### 10.8 Custom Business Metrics

Track domain-specific metrics:

```javascript
// utils/businessMetrics.js
const client = require('prom-client');
const { register } = require('../middleware/metrics');

const userRegistrations = new client.Counter({
  name: 'user_registrations_total',
  help: 'Total number of user registrations',
  labelNames: ['status']
});

const apiKeyUsage = new client.Counter({
  name: 'api_key_usage_total',
  help: 'API key usage by client',
  labelNames: ['client_id', 'endpoint']
});

const orderValue = new client.Histogram({
  name: 'order_value_dollars',
  help: 'Order values in dollars',
  buckets: [10, 50, 100, 500, 1000, 5000]
});

const activeUsers = new client.Gauge({
  name: 'active_users',
  help: 'Number of currently active users'
});

register.registerMetric(userRegistrations);
register.registerMetric(apiKeyUsage);
register.registerMetric(orderValue);
register.registerMetric(activeUsers);

module.exports = {
  userRegistrations,
  apiKeyUsage,
  orderValue,
  activeUsers
};
```

```javascript
// controllers/authController.js
const { userRegistrations } = require('../utils/businessMetrics');

async function register(req, res) {
  try {
    // Registration logic...
    userRegistrations.labels('success').inc();
    res.status(201).json({ user });
  } catch (error) {
    userRegistrations.labels('failure').inc();
    throw error;
  }
}
```

### 10.9 Uptime Monitoring

Use external services to monitor availability:

**Popular Options:**
- **Pingdom** - Synthetic monitoring from multiple locations
- **UptimeRobot** - Free tier available, simple setup
- **StatusCake** - Comprehensive monitoring and alerting
- **Better Uptime** - Modern interface with status pages

**Configuration Example (UptimeRobot):**
- Monitor URL: `https://api.yourdomain.com/health`
- Check interval: 5 minutes
- Alert contacts: Email, SMS, Slack
- Expected status code: 200
- Timeout: 30 seconds

